{
  "name": "EcoGuardian AI",
  "description": "An AI-powered environmental and wildlife incident reporting platform that uses computer vision to automatically assess land damage, illegal activities, and injured wildlife.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum IncidentType {
  LAND_DAMAGE = 'Land Damage',
  ILLEGAL_LOGGING = 'Illegal Logging',
  INJURED_WILDLIFE = 'Injured Wildlife',
  ROAD_ACCIDENT = 'Animal Road Accident',
  POLLUTION = 'Pollution',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export interface Report {
  id: string;
  type: IncidentType;
  severity: Severity;
  description: string;
  location: {
    lat: number;
    lng: number;
    address?: string;
  };
  timestamp: Date;
  imageUrl?: string;
  status: 'pending' | 'verified' | 'resolved';
  reporterId: string;
  aiInsights?: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  points: number;
  reportsCount: number;
  avatar?: string;
}

export interface AIAnalysisResult {
  detectedType: IncidentType;
  severity: Severity;
  explanation: string;
  recommendedAction: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysisResult, IncidentType, Severity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeEnvironmentalImage = async (base64Image: string): Promise<AIAnalysisResult> => {
  const model = 'gemini-3-flash-preview';

  const response = await ai.models.generateContent({
    model,
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: `Analyze this image for environmental or wildlife concerns. 
            Identify if it shows land damage, illegal tree cutting, injured animals, or road accidents. 
            Assess the severity and provide a short explanation and recommended immediate action.`,
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedType: {
            type: Type.STRING,
            description: "Category of the incident: Land Damage, Illegal Logging, Injured Wildlife, Animal Road Accident, Pollution, or Other",
          },
          severity: {
            type: Type.STRING,
            description: "Severity level: Low, Medium, High, or Critical",
          },
          explanation: {
            type: Type.STRING,
            description: "Concise description of what the AI sees",
          },
          recommendedAction: {
            type: Type.STRING,
            description: "A professional recommendation for the user or authorities",
          },
        },
        required: ["detectedType", "severity", "explanation", "recommendedAction"],
      },
    },
  });

  const text = response.text;
  try {
    return JSON.parse(text) as AIAnalysisResult;
  } catch (error) {
    console.error("Failed to parse AI response", text);
    throw new Error("Could not interpret AI analysis.");
  }
};

export const generateCommunityUpdate = async (recentReports: any[]) => {
  const model = 'gemini-3-flash-preview';
  const prompt = `Based on these recent environmental reports in the area: ${JSON.stringify(recentReports)}, 
  write a short, inspiring 2-sentence summary for a community dashboard that encourages students and the public to stay involved.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt
  });

  return response.text;
};

import React, { useState, useRef } from 'react';
import { analyzeEnvironmentalImage } from '../services/geminiService';
import { AIAnalysisResult, IncidentType, Severity, Report } from '../types';

interface ReportWizardProps {
  onComplete: (report: Partial<Report>) => void;
}

const ReportWizard: React.FC<ReportWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AIAnalysisResult | null>(null);
  const [description, setDescription] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImage(base64);
        setStep(2);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartAnalysis = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeEnvironmentalImage(base64Data);
      setAnalysis(result);
      setStep(3);
    } catch (err) {
      alert("AI analysis failed. Please fill manually.");
      setStep(3);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSubmit = () => {
    onComplete({
      type: analysis?.detectedType || IncidentType.OTHER,
      severity: analysis?.severity || Severity.MEDIUM,
      description: description || analysis?.explanation || '',
      imageUrl: image || undefined,
      aiInsights: analysis?.explanation,
      timestamp: new Date(),
    });
  };

  return (
    <div className="bg-white rounded-3xl p-6 shadow-xl max-w-xl mx-auto border border-emerald-100">
      <div className="flex items-center gap-4 mb-8">
        {[1, 2, 3].map((s) => (
          <div key={s} className="flex-1 h-1.5 rounded-full bg-slate-100 overflow-hidden">
            <div className={`h-full transition-all duration-500 ${step >= s ? 'bg-emerald-500' : 'bg-transparent'}`} />
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="text-center py-12">
          <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-emerald-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold mb-2">Capture an Incident</h2>
          <p className="text-slate-500 mb-8 px-4">Help us protect nature. Upload a photo of the environmental problem you've noticed.</p>
          <input 
            type="file" 
            accept="image/*" 
            className="hidden" 
            ref={fileInputRef}
            onChange={handleFileChange}
          />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2"
          >
            Upload or Take Photo
          </button>
        </div>
      )}

      {step === 2 && image && (
        <div className="text-center">
          <img src={image} className="w-full aspect-square object-cover rounded-2xl mb-6 shadow-md" alt="Preview" />
          <h2 className="text-xl font-bold mb-2">Analyze with AI?</h2>
          <p className="text-slate-500 mb-8">Our AI can automatically detect incident type, severity, and recommend actions.</p>
          <div className="flex gap-4">
            <button 
              disabled={analyzing}
              onClick={handleStartAnalysis}
              className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {analyzing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Analyzing...
                </>
              ) : (
                <>
                   <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a8 8 0 100 16 8 8 0 000-16zm1 11H9v-2h2v2zm0-4H9V5h2v4z"></path></svg>
                   AI Deep Scan
                </>
              )}
            </button>
            <button 
              disabled={analyzing}
              onClick={() => setStep(3)}
              className="px-6 border border-slate-200 text-slate-600 font-bold py-3 rounded-xl hover:bg-slate-50"
            >
              Skip
            </button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-6">
          <div className="flex items-center gap-3">
             <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
               <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" strokeWidth="2"/></svg>
             </div>
             <div>
               <h2 className="text-xl font-bold">Review Report</h2>
               <p className="text-xs text-slate-400">AI-suggested details below</p>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Type</label>
              <div className="bg-emerald-50 border border-emerald-100 rounded-lg p-3 font-semibold text-emerald-800">
                {analysis?.detectedType || 'Select Type'}
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Severity</label>
              <div className={`rounded-lg p-3 font-semibold border ${
                analysis?.severity === Severity.CRITICAL ? 'bg-red-50 text-red-700 border-red-100' :
                analysis?.severity === Severity.HIGH ? 'bg-orange-50 text-orange-700 border-orange-100' :
                'bg-blue-50 text-blue-700 border-blue-100'
              }`}>
                {analysis?.severity || 'Standard'}
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Analysis Result</label>
            <p className="text-sm bg-slate-50 p-3 rounded-xl border border-slate-100 italic text-slate-600">
              "{analysis?.explanation || 'No AI insight available.'}"
            </p>
          </div>

          {analysis?.recommendedAction && (
             <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 flex gap-3">
               <svg className="w-5 h-5 text-amber-600 shrink-0" fill="currentColor" viewBox="0 0 20 20"><path d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"/></svg>
               <div>
                  <h4 className="text-sm font-bold text-amber-900">Recommended Action</h4>
                  <p className="text-sm text-amber-800">{analysis.recommendedAction}</p>
               </div>
             </div>
          )}

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Additional Notes</label>
            <textarea 
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Any other details authorities should know..."
              className="w-full bg-slate-50 border border-slate-100 rounded-xl p-4 focus:ring-2 focus:ring-emerald-500 focus:outline-none min-h-[100px]"
            />
          </div>

          <button 
            onClick={handleSubmit}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all"
          >
            Submit Report
          </button>
        </div>
      )}
    </div>
  );
};

export default ReportWizard;

