          <div className="space-y-4">
            <button 
              onClick={handleGoogleLogin}
              className="w-full py-4 px-6 border-2 border-slate-100 rounded-2xl flex items-center justify-center gap-3 font-bold text-slate-700 hover:bg-slate-50 hover:border-emerald-200 transition-all active:scale-95"
