      };

      setUser(authenticatedUser);
      setIsAuthenticated(true);
    } catch (e) {
      alert("Authentication failed. Please try again.");
    }
  };

  const handleDemoLogin = () => {
    setUser(MOCK_USER);
    setIsAuthenticated(true);
  };

  const handleReportComplete = (newReportData: Partial<Report>) => {
    const completeReport: Report = {
      ...newReportData,
      id: Math.random().toString(36).substr(2, 9),
      status: 'pending',
      reporterId: user?.id || 'anon',
    } as Report;

    setReports([completeReport, ...reports]);
    setUser(prev => prev ? ({ ...prev, points: prev.points + 50, reportsCount: prev.reportsCount + 1 }) : null);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
