      {activeTab === 'dashboard' && (
        <Dashboard reports={reports} onNewReport={() => setActiveTab('report')} />
      )}

      {activeTab === 'report' && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <ReportWizard onComplete={handleReportComplete} />
        </div>
      )}

      {activeTab === 'reports' && (
        <div className="space-y-6 max-w-2xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
           <div className="flex items-center justify-between">
              <h2 className="text-2xl font-bold">Recent Incident Feed</h2>
              <div className="flex gap-2">
                <button className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-xs font-bold">Filter</button>
              </div>
           </div>
           {reports.map((report) => (
             <div key={report.id} className="bg-white rounded-[2rem] overflow-hidden border border-slate-200 shadow-sm transition-hover hover:shadow-xl transition-all duration-300">
               <div className="p-5 flex items-center gap-3">
                  <img src={report.reporterId === user?.id ? user.avatar : `https://picsum.photos/seed/${report.reporterId}/40/40`} className="w-10 h-10 rounded-full border border-emerald-100" alt="User" />
                  <div className="flex-1">
                    <p className="text-sm font-bold">{report.reporterId === user?.id ? 'You' : `Guardian #${report.reporterId.slice(-4)}`}</p>
                    <p className="text-xs text-slate-400">{new Date(report.timestamp).toLocaleString()}</p>
                  </div>
                  <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                    report.status === 'verified' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {report.status}
                  </span>
               </div>
               {report.imageUrl && (
                 <img src={report.imageUrl} className="w-full h-72 object-cover border-y border-slate-50" alt="Incident" />
               )}
               <div className="p-6">
                 <div className="flex items-center gap-2 mb-3">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${
                      report.severity === Severity.CRITICAL ? 'bg-red-600 text-white' : 'bg-slate-800 text-white'
                    }`}>
                      {report.severity}
                    </span>
                    <span className="text-sm font-bold text-slate-800">{report.type}</span>
                 </div>
                 <p className="text-slate-600 mb-6 leading-relaxed">{report.description}</p>
                 {report.aiInsights && (
                    <div className="bg-indigo-50/40 p-5 rounded-2xl border border-indigo-100/50 flex gap-4">
                      <div className="w-8 h-8 bg-indigo-100 rounded-xl flex items-center justify-center shrink-0">
                        <svg className="w-4 h-4 text-indigo-600" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a8 8 0 100 16 8 8 0 000-16zm1 11H9v-2h2v2zm0-4H9V5h2v4z"></path></svg>
                      </div>
