export const loginUser = async (email: string, password: string, role: UserRole): Promise<User> => {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 800));

  const user = MOCK_DB[email.toLowerCase()];

  if (!user || user.role !== role) {
    throw new Error("Invalid credentials or unauthorized role.");
  }

  // In a real app, we'd check hashed passwords here
  return {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role,
    points: user.points,
    reportsCount: user.reportsCount,
    avatar: user.avatar
  };
};

export const registerUser = async (name: string, email: string, role: UserRole): Promise<User> => {
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (MOCK_DB[email.toLowerCase()]) {
    throw new Error("User already exists with this email.");
  }

  const newUser: User = {
    id: `u-${Math.random().toString(36).substr(2, 5)}`,
    name,
    email: email.toLowerCase(),
    role,
    points: role === 'user' ? 100 : 0, // Sign up bonus for users
    reportsCount: 0,
    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`
  };

  MOCK_DB[email.toLowerCase()] = { ...newUser };

  return newUser;
};

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService';
import { User, UserRole } from '../types';

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      let user;
      if (isRegister) {
        user = await registerUser(name, email, role);
      } else {
        user = await loginUser(email, password, role);
      }
      onLoginSuccess(user);
    } catch (err: any) {
      setError(err.message || "An error occurred during authentication.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-700 flex flex-col items-center justify-center p-6 relative overflow-hidden ${
      role === 'admin' ? 'bg-[#0a0c1a]' : 'bg-[#061e1a]'
    }`}>
      {/* Dynamic Background Elements */}
      <div className={`absolute top-0 left-0 w-full h-full opacity-30 pointer-events-none transition-all duration-1000 ${
        role === 'admin' ? 'bg-indigo-900/20' : 'bg-emerald-900/20'
      }`}>
        <div className={`absolute top-[-10%] left-[-10%] w-[60%] h-[60%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
          role === 'admin' ? 'bg-indigo-500' : 'bg-emerald-500'
        }`} />
        <div className={`absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
          role === 'admin' ? 'bg-blue-500' : 'bg-teal-500'
        }`} style={{animationDelay: '2s'}} />
      </div>

      <div className="w-full max-w-lg bg-white/95 backdrop-blur-2xl rounded-[3rem] p-10 md:p-14 shadow-[0_32px_80px_-16px_rgba(0,0,0,0.6)] relative z-10 border border-white/20 animate-slide-up">

        {/* Role Switcher */}
        <div className="flex bg-slate-100 p-1.5 rounded-2xl mb-12 relative">
          <div className={`absolute top-1.5 bottom-1.5 w-[calc(50%-6px)] rounded-xl transition-all duration-500 ease-out shadow-md ${
            role === 'admin' ? 'translate-x-full bg-indigo-600' : 'translate-x-0 bg-emerald-600'
          }`} />
          <button 
            onClick={() => setRole('user')}
            className={`flex-1 py-3 px-4 rounded-xl text-xs font-black uppercase tracking-[0.15em] z-10 transition-colors duration-500 ${role === 'user' ? 'text-white' : 'text-slate-400'}`}
