          >
            Regional Admin
          </button>
        </div>

        <div className="text-center mb-10">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl transition-all duration-700 transform hover:scale-110 ${
            role === 'admin' ? 'bg-gradient-to-tr from-indigo-600 to-blue-400' : 'bg-gradient-to-tr from-emerald-600 to-teal-400'
          }`}>
            {role === 'admin' ? (
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2"/></svg>
            ) : (
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 002 2h1.5a2.5 2.5 0 012.5 2.5V14M22 12c0 5.523-4.477 10-10 10S2 17.523 2 12 6.477 2 12 2s10 4.477 10 10z" strokeWidth="2"/></svg>
            )}
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">EcoGuardian <span className={role === 'admin' ? 'text-indigo-600' : 'text-emerald-600'}>AI</span></h1>
          <p className="text-slate-500 font-medium text-xs uppercase tracking-[0.2em]">{role === 'admin' ? 'Central Oversight Portal' : 'Environmental Sentinel Network'}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {isRegister && (
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Full Name</label>
              <input 
                type="text" 
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
