    aiInsights: 'Vision analysis confirms heavy machinery treads and fresh timber removal.'
  },
  {
    id: '2',
    type: IncidentType.INJURED_WILDLIFE,
    severity: Severity.CRITICAL,
    description: 'Found a distressed deer with entanglement issues near the creek.',
    location: { lat: 45.520, lng: -122.670 },
    timestamp: new Date(Date.now() - 7200000),
    imageUrl: 'https://images.unsplash.com/photo-1484406566174-9da000fda645?auto=format&fit=crop&q=80&w=800',
