    aiInsights: 'Distress detected. Anatomy scan suggests limb entanglement. Immediate rescue recommended.'
  }
];

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>(INITIAL_REPORTS);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    setIsAuthenticated(true);
  };

  const handleReportComplete = (newReportData: Partial<Report>) => {
    const completeReport: Report = {
      ...newReportData,
      id: Math.random().toString(36).substr(2, 9),
      status: 'pending',
      reporterId: user?.id || 'anon',
    } as Report;

    setReports([completeReport, ...reports]);
    if (user && user.role === 'user') {
      setUser(prev => prev ? ({ ...prev, points: prev.points + 100, reportsCount: prev.reportsCount + 1 }) : null);
    }
    setActiveTab('reports');
  };

  const handleUpdateStatus = (id: string, newStatus: Report['status']) => {
    setReports(prev => prev.map(r => r.id === id ? { ...r, status: newStatus } : r));
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setActiveTab('dashboard');
  };

  if (!isAuthenticated) {
    return <Login onLoginSuccess={handleAuthSuccess} />;
  }

  return (
    <Layout 
      user={user!} 
      onLogout={handleLogout} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
    >
      <div className="max-w-6xl mx-auto w-full">
        {activeTab === 'dashboard' && (
          <Dashboard reports={reports} onNewReport={() => setActiveTab('report')} />
