                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                    {user?.role === 'admin' ? 'Global Overseer Feed' : 'Active Sentinel Feed'}
                  </h2>
                  <p className="text-slate-500 font-medium">Real-time environmental risk auditing via AI</p>
               </div>
               <div className="flex gap-2 bg-slate-50 p-1 rounded-2xl border border-slate-100">
