                <div key={report.id} className="bg-white rounded-[3rem] overflow-hidden border border-slate-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] hover:shadow-[0_8px_40px_rgb(0,0,0,0.1)] transition-all duration-500 group">
                  <div className="flex flex-col lg:flex-row">
