import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService';
import { User, UserRole } from '../types';

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setLoading(true);

    try {
      if (isRegister) {
        // Register flow: Create account but don't log in yet
        await registerUser(name, email, role);
        setSuccessMessage('Registration successful! Please sign in with your credentials.');
        setIsRegister(false); // Switch back to login view
        setPassword(''); // Clear password for security
        setName(''); // Clear name
      } else {
        // Login flow: Authenticate and proceed to app
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err: any) {
      setError(err.message || "An error occurred during authentication.");
    } finally {
      setLoading(false);
    }
  };

  const toggleView = () => {
    setIsRegister(!isRegister);
    setError('');
    setSuccessMessage('');
  };

  const handleRoleChange = (newRole: UserRole) => {
    setRole(newRole);
    setError('');
    setSuccessMessage('');
  };

  return (
    <div className={`min-h-screen transition-colors duration-700 flex flex-col items-center justify-center p-6 relative overflow-hidden ${
      role === 'admin' ? 'bg-[#0a0c1a]' : 'bg-[#061e1a]'
    }`}>
      {/* Dynamic Background Elements */}
      <div className={`absolute top-0 left-0 w-full h-full opacity-30 pointer-events-none transition-all duration-1000 ${
        role === 'admin' ? 'bg-indigo-900/20' : 'bg-emerald-900/20'
      }`}>
        <div className={`absolute top-[-10%] left-[-10%] w-[60%] h-[60%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
          role === 'admin' ? 'bg-indigo-500' : 'bg-emerald-500'
        }`} />
        <div className={`absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
          role === 'admin' ? 'bg-blue-500' : 'bg-teal-500'
        }`} style={{animationDelay: '2s'}} />
      </div>

      <div className="w-full max-w-lg bg-white/95 backdrop-blur-2xl rounded-[3rem] p-10 md:p-14 shadow-[0_32px_80px_-16px_rgba(0,0,0,0.6)] relative z-10 border border-white/20 animate-slide-up">

        {/* Role Switcher */}
        <div className="flex bg-slate-100 p-1.5 rounded-2xl mb-12 relative">
          <div className={`absolute top-1.5 bottom-1.5 w-[calc(50%-6px)] rounded-xl transition-all duration-500 ease-out shadow-md ${
            role === 'admin' ? 'translate-x-full bg-indigo-600' : 'translate-x-0 bg-emerald-600'
          }`} />
          <button 
            type="button"
            onClick={() => handleRoleChange('user')}
            className={`flex-1 py-3 px-4 rounded-xl text-xs font-black uppercase tracking-[0.15em] z-10 transition-colors duration-500 ${role === 'user' ? 'text-white' : 'text-slate-400'}`}
          >
            Sentinel User
          </button>
          <button 
            type="button"
            onClick={() => handleRoleChange('admin')}
            className={`flex-1 py-3 px-4 rounded-xl text-xs font-black uppercase tracking-[0.15em] z-10 transition-colors duration-500 ${role === 'admin' ? 'text-white' : 'text-slate-400'}`}
          >
            Regional Admin
          </button>
        </div>

        <div className="text-center mb-10">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl transition-all duration-700 transform hover:scale-110 ${
            role === 'admin' ? 'bg-gradient-to-tr from-indigo-600 to-blue-400' : 'bg-gradient-to-tr from-emerald-600 to-teal-400'
          }`}>
            {role === 'admin' ? (
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2"/></svg>
            ) : (
              <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 002 2h1.5a2.5 2.5 0 012.5 2.5V14M22 12c0 5.523-4.477 10-10 10S2 17.523 2 12 6.477 2 12 2s10 4.477 10 10z" strokeWidth="2"/></svg>
            )}
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">EcoGuardian <span className={role === 'admin' ? 'text-indigo-600' : 'text-emerald-600'}>AI</span></h1>
          <p className="text-slate-500 font-medium text-xs uppercase tracking-[0.2em]">{role === 'admin' ? 'Central Oversight Portal' : 'Environmental Sentinel Network'}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {isRegister && (
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Full Name</label>
              <input 
                type="text" 
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Guardian Name" 
                className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all font-bold text-slate-800"
              />
            </div>
          )}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Email Address</label>
            <input 
              type="email" 
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="name@ecoguard.ai" 
              className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all font-bold text-slate-800"
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Security Key</label>
            <input 
              type="password" 
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••" 
              className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-all font-bold text-slate-800"
            />
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 text-xs font-bold p-4 rounded-xl border border-red-100 animate-shake">
              {error}
            </div>
          )}

          {successMessage && (
            <div className={`text-xs font-bold p-4 rounded-xl border animate-in fade-in slide-in-from-top-2 ${
              role === 'admin' ? 'bg-indigo-50 text-indigo-700 border-indigo-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100'
            }`}>
              {successMessage}
            </div>
          )}

          <button 
            disabled={loading}
            type="submit"
            className={`w-full py-5 rounded-2xl font-black text-white shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-3 mt-4 ${
              role === 'admin' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-500/30' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-500/30'
            }`}
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
            ) : (
              isRegister ? 'Initialize Account' : `Authorize ${role === 'admin' ? 'Admin' : 'User'}`
            )}
          </button>
        </form>

        <div className="mt-8 text-center space-y-4">
          <button 
            type="button"
            onClick={toggleView}
            className="text-xs font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest transition-colors"
          >
            {isRegister ? 'Already have credentials? Log In' : 'New Sentinel? Register Here'}
          </button>

          <div className="pt-6 border-t border-slate-50 flex justify-center items-center gap-6 opacity-40 grayscale">
            <img src="https://upload.wikimedia.org/wikipedia/commons/9/93/MongoDB_Logo.svg" className="h-4" alt="MongoDB" />
            <img src="https://upload.wikimedia.org/wikipedia/commons/d/d9/Node.js_logo.svg" className="h-4" alt="Node" />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

export enum IncidentType {
  LAND_DAMAGE = 'Land Damage',
  ILLEGAL_LOGGING = 'Illegal Logging',
  INJURED_WILDLIFE = 'Injured Wildlife',
  ROAD_ACCIDENT = 'Animal Road Accident',
  POLLUTION = 'Pollution',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export type UserRole = 'user' | 'admin' | 'authority';

export type ReportStatus = 'pending' | 'verified' | 'assigned' | 'investigating' | 'resolved' | 'rejected';

export interface TimelineEvent {
  status: ReportStatus;
  timestamp: Date;
  message: string;
  actor: string;
}

export interface Report {
  id: string;
  type: IncidentType;
  severity: Severity;
  description: string;
  location: {
    lat: number;
    lng: number;
    address?: string;
  };
  timestamp: Date;
  imageUrl?: string;
  status: ReportStatus;
  reporterId: string;
  assignedAuthority?: string;
  aiInsights?: string;
  timeline: TimelineEvent[];
  resolutionDetails?: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  points: number;
  reportsCount: number;
  avatar?: string;
}

export interface AIAnalysisResult {
  detectedType: IncidentType;
  severity: Severity;
  explanation: string;
  recommendedAction: string;
}

