const AUTHORITIES = [
  "Forestry Commission",
  "Wildlife Rescue Unit",
  "Environmental Protection Agency",
  "Municipal Police Force",
  "Water Quality Board"
];

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>(INITIAL_REPORTS);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    setIsAuthenticated(true);
  };

  const handleReportComplete = (newReportData: Partial<Report>) => {
    const completeReport: Report = {
      ...newReportData,
      id: Math.random().toString(36).substr(2, 9),
      status: 'pending',
      reporterId: user?.id || 'anon',
      timeline: [{ 
        status: 'pending', 
        timestamp: new Date(), 
        message: 'Report initialized and queued for verification.', 
        actor: user?.name || 'Sentinel' 
      }]
    } as Report;

    setReports([completeReport, ...reports]);
    if (user && user.role === 'user') {
      setUser(prev => prev ? ({ ...prev, points: prev.points + 100, reportsCount: prev.reportsCount + 1 }) : null);
    }
    setActiveTab('reports');
  };

  const handleUpdateStatus = (id: string, newStatus: ReportStatus, message: string, actor: string, extraData?: any) => {
    setReports(prev => prev.map(r => {
      if (r.id === id) {
        const newEvent: TimelineEvent = { status: newStatus, timestamp: new Date(), message, actor };
        return { 
          ...r, 
          status: newStatus, 
          timeline: [...r.timeline, newEvent],
          ...extraData 
        };
      }
      return r;
    }));
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setActiveTab('dashboard');
  };

  if (!isAuthenticated) {
    return <Login onLoginSuccess={handleAuthSuccess} />;
  }

  return (
    <Layout user={user!} onLogout={handleLogout} activeTab={activeTab} setActiveTab={setActiveTab}>
      <div className="max-w-6xl mx-auto w-full pb-20">
        {activeTab === 'dashboard' && <Dashboard reports={reports} onNewReport={() => setActiveTab('report')} />}
        {activeTab === 'report' && <div className="py-4"><ReportWizard onComplete={handleReportComplete} /></div>}
        {activeTab === 'leaderboard' && <SystemInsights />}

        {activeTab === 'reports' && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
