               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Case Resolution Feed</h2>
                  <p className="text-slate-500 font-medium">Monitoring the end-to-end lifecycle of environmental interventions.</p>
               </div>
               <div className="flex bg-slate-50 p-1.5 rounded-2xl border border-slate-100">
                  <span className="px-6 py-2.5 bg-white shadow-sm rounded-xl text-xs font-black text-slate-800">Live Queue</span>
               </div>
            </div>

            <div className="grid grid-cols-1 gap-12">
              {reports.map((report) => (
                <div key={report.id} className="bg-white rounded-[3.5rem] overflow-hidden border border-slate-100 shadow-[0_20px_50px_rgba(0,0,0,0.04)] group">
                  <div className="flex flex-col xl:flex-row">
                    {/* Visual & Status Section */}
