      { status: 'pending', timestamp: new Date(Date.now() - 3600000), message: 'Report submitted by Sentinel #99', actor: 'Sentinel' },
      { status: 'verified', timestamp: new Date(Date.now() - 3000000), message: 'AI and Admin verified the incident validity.', actor: 'Admin' },
      { status: 'assigned', timestamp: new Date(Date.now() - 2400000), message: 'Case dispatched to Forestry Commission.', actor: 'Admin' },
