const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>(INITIAL_REPORTS);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    setIsAuthenticated(true);
  };

  const handleUpdateStatus = (id: string, newStatus: ReportStatus, message: string, actor: string, extraData?: any) => {
    setReports(prev => prev.map(r => {
      if (r.id === id) {
        const newEvent: TimelineEvent = { status: newStatus, timestamp: new Date(), message, actor, ...extraData?.eventProps };
        return { ...r, status: newStatus, timeline: [...r.timeline, newEvent], ...extraData };
      }
      return r;
    }));
  };

  if (!isAuthenticated) return <Login onLoginSuccess={handleAuthSuccess} />;

  return (
    <Layout user={user!} onLogout={() => setIsAuthenticated(false)} activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard reports={reports} onNewReport={() => setActiveTab('report')} />}
      {activeTab === 'report' && <ReportWizard onComplete={(data) => {
        const nr: Report = { ...data, id: Math.random().toString(36).substr(2, 9), status: 'pending', reporterId: user!.id, timeline: [{ status: 'pending', timestamp: new Date(), message: 'Initial data submission.', actor: user!.name }] } as Report;
        setReports([nr, ...reports]);
        setActiveTab('reports');
      }} />}
      {activeTab === 'reports' && (
        <div className="space-y-10">
          <div className="flex justify-between items-center bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
             <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Active Operations</h2>
                <p className="text-slate-500 font-medium">Real-time status of ecological interventions.</p>
             </div>
          </div>
          <div className="grid gap-10">
            {reports.map(r => (
              <div key={r.id} className="bg-white rounded-[3rem] border border-slate-100 shadow-xl overflow-hidden flex flex-col md:flex-row">
                 <div className="md:w-1/3 h-64 md:h-auto relative">
                    <img src={r.imageUrl} className="w-full h-full object-cover" />
                    <div className="absolute top-6 left-6 px-4 py-2 bg-white/20 backdrop-blur-md rounded-xl text-white text-[10px] font-black uppercase tracking-widest">{r.type}</div>
                 </div>
                 <div className="md:w-2/3 p-10">
                    <div className="flex justify-between items-start mb-8">
                       <span className={`px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest ${r.status === 'resolved' ? 'bg-emerald-100 text-emerald-700' : 'bg-indigo-100 text-indigo-700'}`}>
                          {r.status}
                       </span>
                       <span className="text-[10px] font-black text-slate-400 uppercase">Case ID: {r.id}</span>
                    </div>
                    <p className="text-lg font-bold text-slate-800 mb-8 leading-relaxed italic">"{r.description}"</p>

                    {/* Role Actions */}
                    <div className="pt-8 border-t border-slate-50 flex flex-wrap gap-4">
                       {user?.role === 'admin' && r.status === 'pending' && (
                         <button onClick={() => handleUpdateStatus(r.id, 'verified', 'Admin verified the emergency.', 'Admin Dispatcher')} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs hover:bg-indigo-700 transition-all">Verify & Escalate</button>
                       )}
                       {user?.role === 'admin' && r.status === 'verified' && (
                         <div className="flex gap-2">
                            {AUTHORITIES.map(auth => (
                              <button key={auth} onClick={() => handleUpdateStatus(r.id, 'assigned', `Escalated to ${auth}.`, 'Admin Dispatcher', { assignedAuthorityId: auth })} className="px-4 py-3 bg-slate-100 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-50 hover:text-indigo-600 transition-all">{auth}</button>
                            ))}
                         </div>
                       )}
                       {user?.role === 'authority' && r.status === 'assigned' && user?.organization === r.assignedAuthorityId && (
                         <button onClick={() => handleUpdateStatus(r.id, 'investigating', 'Authority claimed the case.', user!.organization || 'Agency')} className="px-8 py-4 bg-amber-600 text-white rounded-2xl font-black text-xs hover:bg-amber-700 transition-all">Claim Task & Log Presence</button>
                       )}
                       {user?.role === 'authority' && r.status === 'investigating' && user?.organization === r.assignedAuthorityId && (
                         <button onClick={() => handleUpdateStatus(r.id, 'resolved', 'Incident successfully mitigated.', user!.organization || 'Agency', { eventProps: { actionTaken: 'Field Mitigation Complete' } })} className="px-8 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs hover:bg-emerald-700 transition-all">Finalize Resolution</button>
                       )}
                    </div>

                    {/* Timeline */}
                    <div className="mt-8 space-y-4">
                      {r.timeline.map((evt, idx) => (
                        <div key={idx} className="flex gap-4 items-center">
                           <div className="w-1.5 h-1.5 rounded-full bg-slate-200" />
                           <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{evt.actor}: <span className="text-slate-900">{evt.message}</span></p>
                           {evt.actionTaken && <span className="px-3 py-1 bg-emerald-50 text-emerald-600 text-[8px] font-black rounded-lg">ACTION: {evt.actionTaken}</span>}
                        </div>
                      ))}
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}
      {activeTab === 'leaderboard' && <SystemInsights />}
      {activeTab === 'notes' && <Resources />}
    </Layout>
  );
};

export default App;

