}

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export type UserRole = 'user' | 'admin' | 'authority';

export type ReportStatus = 'pending' | 'verified' | 'assigned' | 'investigating' | 'resolved' | 'rejected';

export interface TimelineEvent {
  status: ReportStatus;
  timestamp: Date;
  message: string;
  actor: string;
  actionTaken?: string;
}

export interface Report {
  id: string;
