          ...r, 
          status: newStatus, 
          timeline: [...r.timeline, newEvent], 
          ...extraData 
        };
      }
      return r;
    }));
  };

  if (!isAuthenticated) return <Login onLoginSuccess={handleAuthSuccess} />;

  return (
    <Layout user={user!} onLogout={() => setIsAuthenticated(false)} activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard reports={reports} onNewReport={() => setActiveTab('report')} onNavigate={(t) => setActiveTab(t)} />}

      {activeTab === 'report' && <ReportWizard onComplete={(data) => {
        const nr: Report = { 
          ...data, 
          id: `R-${Math.floor(Math.random()*900)+100}`, 
          status: 'pending', 
          reporterId: user!.id, 
          timeline: [{ status: 'pending', timestamp: new Date(), message: 'Incident data queued for verification.', actor: user!.name }] 
        } as Report;
        setReports([nr, ...reports]);
        setActiveTab('reports');
      }} />}

      {activeTab === 'reports' && (
        <div className="space-y-12">
          <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
             <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Operation Feed</h2>
                <p className="text-slate-500 font-medium">Monitoring real-world intervention cycles.</p>
             </div>
             <div className="flex bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
                <span className="px-6 py-2.5 bg-white shadow-sm rounded-xl text-xs font-black text-slate-800">Live Grid</span>
             </div>
          </div>

          <div className="grid gap-12">
            {reports.map(r => (
              <div key={r.id} className="bg-white rounded-[3.5rem] border border-slate-100 shadow-2xl overflow-hidden flex flex-col xl:flex-row transition-all hover:shadow-emerald-900/10">
                 <div className="xl:w-1/3 h-96 xl:h-auto relative">
                    <img src={r.imageUrl} className="w-full h-full object-cover" alt="Incident Evidence" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent" />
                    <div className="absolute bottom-10 left-10">
                       <span className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest bg-emerald-500 text-white`}>{r.type}</span>
                       <h3 className="text-white text-2xl font-black mt-4">{r.location.address}</h3>
                    </div>
                 </div>

                 <div className="xl:w-2/3 p-12 flex flex-col">
                    <div className="flex justify-between items-start mb-8">
                       <div className="flex items-center gap-4">
                          <div className={`w-3 h-3 rounded-full animate-pulse ${r.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                          <p className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">STATUS: <span className="text-slate-900">{r.status}</span></p>
                       </div>
                       <p className="text-[10px] font-black text-slate-300 uppercase">UID: {r.id}</p>
                    </div>

                    <p className="text-xl font-bold text-slate-800 mb-10 leading-relaxed italic">"{r.description}"</p>

                    {/* Authority Action Hub */}
                    <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100 mb-10">
                       <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Escalation Controls</h4>
                       <div className="flex flex-wrap gap-4">
                          {user?.role === 'admin' && r.status === 'pending' && (
                            <button onClick={() => handleUpdateStatus(r.id, 'verified', 'Command clearance granted.', 'Chief Warden')} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all">Verify & Escalate</button>
                          )}

                          {user?.role === 'admin' && r.status === 'verified' && (
                            <div className="flex flex-wrap gap-3">
                               {AUTHORITIES.map(auth => (
                                 <button key={auth} onClick={() => handleUpdateStatus(r.id, 'assigned', `Assigned to ${auth}.`, 'Admin Dispatch', { assignedAuthorityId: auth })} className="px-5 py-3 bg-white border border-slate-200 rounded-xl text-[9px] font-black uppercase tracking-widest hover:border-indigo-600 hover:text-indigo-600 transition-all">Dispatch: {auth}</button>
                               ))}
                            </div>
                          )}

                          {user?.role === 'authority' && r.status === 'assigned' && user?.organization === r.assignedAuthorityId && (
                            <button onClick={() => handleUpdateStatus(r.id, 'investigating', 'Authority claimed for field audit.', user!.organization || 'Agency')} className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs hover:bg-black transition-all">Acknowledge Tasking</button>
                          )}

                          {user?.role === 'authority' && r.status === 'investigating' && user?.organization === r.assignedAuthorityId && (
                            <div className="flex flex-wrap gap-3">
                               {FIELD_ACTIONS.map(act => (
                                 <button key={act} onClick={() => handleUpdateStatus(r.id, 'resolved', 'Operation successfully terminated.', user!.organization || 'Agency', { actionTaken: act, resolutionDetails: `Intervention: ${act} completed.` })} className="px-5 py-3 bg-emerald-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-emerald-700 transition-all">Action: {act}</button>
                               ))}
                            </div>
                          )}
                       </div>
                    </div>

                    {/* Operational Timeline */}
                    <div className="space-y-6">
                      <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Chronological Log</h4>
                      <div className="relative pl-8 space-y-6">
                         <div className="absolute left-1.5 top-2 bottom-2 w-0.5 bg-slate-100" />
                         {r.timeline.map((evt, idx) => (
                           <div key={idx} className="relative">
                              <div className={`absolute -left-[1.625rem] top-1 w-3 h-3 rounded-full border-4 border-white ${idx === r.timeline.length-1 ? 'bg-emerald-500' : 'bg-slate-200'}`} />
                              <div className="flex justify-between items-start">
                                 <div>
                                    <p className="text-sm font-black text-slate-900">{evt.message}</p>
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{evt.actor}</p>
                                 </div>
                                 <span className="text-[9px] font-bold text-slate-300">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                              </div>
                              {evt.actionTaken && (
                                <div className="mt-3 inline-flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-lg text-[9px] font-black uppercase tracking-widest">
                                   <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4" strokeWidth="3"/></svg>
                                   Tactical Unit: {evt.actionTaken}
                                </div>
                              )}
                           </div>
                         ))}
                      </div>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

export default App;

