import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ReportWizard from './components/ReportWizard';
import Login from './components/Login';
import SystemInsights from './components/SystemInsights';
import Resources from './components/Resources';
import { User, Report, Severity, IncidentType, ReportStatus, TimelineEvent } from './types';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];
const FIELD_ACTIONS = ["Drone Reconnaissance", "Physical Containment", "Medical Intervention", "Legal Documentation", "Suspect Pursuit"];

const INITIAL_REPORTS: Report[] = [
  {
    id: 'R-102',
    type: IncidentType.ILLEGAL_LOGGING,
    severity: Severity.HIGH,
    description: 'Unauthorized logging machinery detected in Sector 42 Protected Zone.',
    location: { lat: 45.523, lng: -122.676, address: "Sector 42, Northern Ridge" },
    timestamp: new Date(Date.now() - 3600000),
    imageUrl: 'https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?auto=format&fit=crop&q=80&w=800',
    status: 'investigating',
    reporterId: 'user-99',
    assignedAuthorityId: 'Forestry Commission',
    aiInsights: 'Vision analysis confirms industrial-grade equipment and fresh timber removal.',
    timeline: [
      { status: 'pending', timestamp: new Date(Date.now() - 3600000), message: 'Report submitted via Sentinel App.', actor: 'User Sentinel' },
      { status: 'verified', timestamp: new Date(Date.now() - 3000000), message: 'Command verified incident via Satellite cross-reference.', actor: 'Chief Warden' },
      { status: 'assigned', timestamp: new Date(Date.now() - 2400000), message: 'Dispatched to Forestry Commission.', actor: 'Admin' },
      { status: 'investigating', timestamp: new Date(Date.now() - 1800000), message: 'Field officers deployed for onsite verification.', actor: 'Forestry Commission', actionTaken: 'Physical Recon' }
    ]
