  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setLoading(true);

    try {
      if (isRegister) {
        const newUser = await registerUser(name, email, role);
        // Manually add address for demo as authService doesn't support it yet
        onLoginSuccess({ ...newUser, address });
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
