const MOCK_DB: Record<string, User & { password?: string }> = {
  'admin@ecoguard.ai': {
    id: 'admin-001',
    name: 'Chief Warden',
    email: 'admin@ecoguard.ai',
    role: 'admin',
    points: 0,
    reportsCount: 0,
    avatar: 'https://api.dicebear.com/7.x/bottts/svg?seed=Admin',
    password: 'admin'
  },
  'rescue@wildlife.gov': {
    id: 'auth-001',
    name: 'Sarah Ranger',
    email: 'rescue@wildlife.gov',
    role: 'authority',
    organization: 'Wildlife Rescue Unit',
    points: 0,
    reportsCount: 42,
    avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sarah',
    password: 'rescue'
  }
};

export const loginUser = async (email: string, password: string, role: UserRole): Promise<User> => {
  await new Promise(resolve => setTimeout(resolve, 800));
  const user = MOCK_DB[email.toLowerCase()];

  if (!user || user.role !== role) {
    throw new Error("Invalid credentials or unauthorized role.");
  }

  return {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role,
    points: user.points,
    reportsCount: user.reportsCount,
    avatar: user.avatar,
    organization: user.organization
  };
};

export const registerUser = async (name: string, email: string, role: UserRole): Promise<User> => {
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (MOCK_DB[email.toLowerCase()]) {
    throw new Error("User already exists with this email.");
  }

  const newUser: User = {
    id: `u-${Math.random().toString(36).substr(2, 5)}`,
    name,
    email: email.toLowerCase(),
    role,
    points: role === 'user' ? 100 : 0,
    reportsCount: 0,
    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name}`
  };

  MOCK_DB[email.toLowerCase()] = { ...newUser };
  return newUser;
};

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService';
import { User, UserRole } from '../types';

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMessage('');
    setLoading(true);

    try {
      if (isRegister) {
        const newUser = await registerUser(name, email, role);
        onLoginSuccess(newUser);
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err: any) {
      setError(err.message || "An error occurred.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-700 flex flex-col items-center justify-center p-6 relative overflow-hidden ${
      role === 'admin' ? 'bg-[#0a0c1a]' : role === 'authority' ? 'bg-[#1a140a]' : 'bg-[#061e1a]'
    }`}>
      {/* Background Decor */}
      <div className="absolute inset-0 opacity-20 pointer-events-none">
         <div className={`absolute top-0 left-0 w-[80%] h-[80%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
           role === 'admin' ? 'bg-indigo-500' : role === 'authority' ? 'bg-amber-500' : 'bg-emerald-500'
         }`} />
      </div>

      <div className="w-full max-w-lg bg-white/95 backdrop-blur-2xl rounded-[3rem] p-10 shadow-2xl relative z-10 border border-white/20 animate-slide-up">

        {/* Role Switcher */}
        <div className="flex bg-slate-100 p-1 rounded-2xl mb-10">
          {(['user', 'admin', 'authority'] as UserRole[]).map((r) => (
            <button 
              key={r}
              type="button"
              onClick={() => {
                setRole(r);
                setError('');
              }}
              className={`flex-1 py-3 px-2 rounded-xl text-[9px] font-black uppercase tracking-wider z-10 transition-all ${
                role === r ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {r === 'authority' ? 'Agency' : r}
            </button>
          ))}
        </div>

        <div className="text-center mb-8">
          <h1 className="text-3xl font-black text-slate-900 mb-2">EcoGuardian <span className={role === 'admin' ? 'text-indigo-600' : role === 'authority' ? 'text-amber-600' : 'text-emerald-600'}>AI</span></h1>
          <p className="text-slate-500 font-medium text-[10px] uppercase tracking-widest">
            {isRegister ? 'New Sentinel Recruitment' : (role === 'authority' ? 'Agency Response Portal' : 'Environmental Intelligence Network')}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {isRegister && (
            <input type="text" required value={name} onChange={(e) => setName(e.target.value)} placeholder="Full Name" className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" />
          )}
          <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" />
          <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" />

          {error && <div className="bg-red-50 text-red-600 text-[10px] font-black p-4 rounded-xl border border-red-100">{error}</div>}
          {successMessage && <div className="bg-emerald-50 text-emerald-700 text-[10px] font-black p-4 rounded-xl border border-emerald-100">{successMessage}</div>}

          <button disabled={loading} type="submit" className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all active:scale-95 disabled:opacity-50 ${
            role === 'admin' ? 'bg-indigo-600 hover:bg-indigo-700' : role === 'authority' ? 'bg-amber-600 hover:bg-amber-700' : 'bg-emerald-600 hover:bg-emerald-700'
          }`}>
            {loading ? 'Processing...' : isRegister ? 'Confirm Recruitment' : 'Enter Command Center'}
          </button>
        </form>

        <button onClick={() => { setIsRegister(!isRegister); setError(''); }} className="w-full mt-6 text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest">
          {isRegister ? 'Already registered? Log in' : 'New Sentinel? Apply Here'}
        </button>
      </div>
    </div>
  );
};

export default Login;

