import React, { useState, useEffect } from 'react';
import { loginUser, registerUser } from '../services/authService';
import { User, UserRole } from '../types';

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successStep, setSuccessStep] = useState(0); // 0: Form, 1: Processing, 2: Success

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const handleRegister = async () => {
    setLoading(true);
    setError('');
    try {
      const newUser = await registerUser(name, email, role);
      setSuccessStep(1);

      // Simulate "Onboarding Steps" for recruiter impression
      setTimeout(() => setSuccessStep(2), 1500);
      setTimeout(() => {
        onLoginSuccess(newUser);
      }, 3500);
    } catch (err: any) {
      setError(err.message || "Registration failed.");
      setLoading(false);
    }
  };

  const handleLogin = async () => {
    setLoading(true);
    setError('');
    try {
      const user = await loginUser(email, password, role);
      onLoginSuccess(user);
    } catch (err: any) {
      setError(err.message || "Invalid credentials.");
      setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isRegister) {
      handleRegister();
    } else {
      handleLogin();
    }
  };

  if (successStep > 0) {
    return (
      <div className="min-h-screen bg-[#061e1a] flex items-center justify-center p-6">
        <div className="w-full max-w-lg bg-white rounded-[3rem] p-12 text-center shadow-2xl animate-slide-up">
          {successStep === 1 ? (
            <div className="space-y-8 py-10">
              <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mx-auto" />
              <h2 className="text-2xl font-black text-slate-900">Finalizing Recruitment...</h2>
              <p className="text-slate-500 font-medium">Syncing with the Global Sentinel Network</p>
            </div>
          ) : (
            <div className="space-y-8 py-10 animate-in fade-in zoom-in duration-500">
              <div className="w-20 h-20 bg-emerald-500 rounded-full flex items-center justify-center mx-auto text-white shadow-lg shadow-emerald-200">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M5 13l4 4L19 7" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round"/></svg>
              </div>
              <div>
                <h2 className="text-3xl font-black text-slate-900 mb-2">Welcome, Sentinel</h2>
                <p className="text-slate-500 font-medium">Your credentials have been verified. Redirecting to Command Center...</p>
              </div>
              <div className="pt-4 flex justify-center gap-2">
                {[1, 2, 3].map(i => (
                  <div key={i} className="w-2 h-2 rounded-full bg-emerald-200 animate-bounce" style={{animationDelay: `${i * 0.2}s`}} />
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen transition-colors duration-700 flex flex-col items-center justify-center p-6 relative overflow-hidden ${
      role === 'admin' ? 'bg-[#0a0c1a]' : role === 'authority' ? 'bg-[#1a140a]' : 'bg-[#061e1a]'
    }`}>
      {/* Background Decor */}
      <div className="absolute inset-0 opacity-20 pointer-events-none">
         <div className={`absolute top-0 left-0 w-[80%] h-[80%] rounded-full blur-[150px] animate-pulse transition-colors duration-1000 ${
           role === 'admin' ? 'bg-indigo-500' : role === 'authority' ? 'bg-amber-500' : 'bg-emerald-500'
         }`} />
      </div>

      <div className="w-full max-w-lg bg-white/95 backdrop-blur-2xl rounded-[3rem] p-10 shadow-2xl relative z-10 border border-white/20 animate-slide-up">

        {/* Role Switcher */}
        <div className="flex bg-slate-100 p-1 rounded-2xl mb-10">
          {(['user', 'admin', 'authority'] as UserRole[]).map((r) => (
            <button 
              key={r}
              type="button"
              onClick={() => {
                setRole(r);
                setError('');
              }}
              className={`flex-1 py-3 px-2 rounded-xl text-[9px] font-black uppercase tracking-wider z-10 transition-all ${
                role === r ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {r === 'authority' ? 'Agency' : r}
            </button>
          ))}
        </div>

        <div className="text-center mb-8">
          <h1 className="text-3xl font-black text-slate-900 mb-2">EcoGuardian <span className={role === 'admin' ? 'text-indigo-600' : role === 'authority' ? 'text-amber-600' : 'text-emerald-600'}>AI</span></h1>
          <p className="text-slate-500 font-medium text-[10px] uppercase tracking-widest">
            {isRegister ? 'New Sentinel Recruitment' : (role === 'authority' ? 'Agency Response Portal' : 'Environmental Intelligence Network')}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {isRegister && (
            <input 
              type="text" 
              required 
              value={name} 
              onChange={(e) => setName(e.target.value)} 
              placeholder="Full Name" 
              className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" 
            />
          )}
          <input 
            type="email" 
            required 
            value={email} 
            onChange={(e) => setEmail(e.target.value)} 
            placeholder="Email Address" 
            className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" 
          />
          <input 
            type="password" 
            required 
            value={password} 
            onChange={(e) => setPassword(e.target.value)} 
            placeholder="Password" 
            className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all" 
          />

          {error && <div className="bg-red-50 text-red-600 text-[10px] font-black p-4 rounded-xl border border-red-100">{error}</div>}

          <button disabled={loading} type="submit" className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all active:scale-95 disabled:opacity-50 ${
            role === 'admin' ? 'bg-indigo-600 hover:bg-indigo-700' : role === 'authority' ? 'bg-amber-600 hover:bg-amber-700' : 'bg-emerald-600 hover:bg-emerald-700'
          }`}>
            {loading ? 'Processing Agent...' : isRegister ? 'Confirm Recruitment' : 'Enter Command Center'}
          </button>
        </form>

        <button 
          onClick={() => { setIsRegister(!isRegister); setError(''); }} 
          className="w-full mt-6 text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-widest"
        >
          {isRegister ? 'Already an agent? Log in' : 'New to the Network? Apply Here'}
        </button>
      </div>
    </div>
  );
};

