        const nr: Report = { 
          ...data, 
          id: `R-${Math.floor(Math.random()*900)+100}`, 
          status: 'pending', 
          reporterId: user!.id, 
          timeline: [{ status: 'pending', timestamp: new Date(), message: 'Incident reported by user.', actor: user!.name }] 
        } as Report;
        setReports([nr, ...reports]);
        setActiveTab('reports');
      }} />}

      {activeTab === 'reports' && (
