                    <div className="flex justify-between items-start mb-8">
                       <div className="flex items-center gap-4">
                          <div className={`w-3 h-3 rounded-full animate-pulse ${r.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                          <p className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">STATUS: <span className="text-slate-900">
                            {r.status === 'solved_by_authority' ? 'Action Complete (Awaiting Admin)' : r.status}
                          </span></p>
                       </div>
                       <p className="text-[10px] font-black text-slate-300 uppercase">UID: {r.id}</p>
                    </div>

                    <p className="text-xl font-bold text-slate-800 mb-10 leading-relaxed italic">"{r.description}"</p>

                    {/* ACTION HUB - Strictly enforcing workflow roles */}
                    <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100 mb-10">
