                       <div className="flex flex-wrap gap-4">
                          {/* ADMIN: Phase 1 - Forwarding to Authority */}
                          {user?.role === 'admin' && r.status === 'pending' && (
                            <div className="space-y-4 w-full">
                               <p className="text-[10px] font-black text-indigo-600 uppercase">Forward to Specialist Agency:</p>
                               <div className="flex flex-wrap gap-3">
                                  {AUTHORITIES.map(auth => (
                                    <button 
                                      key={auth} 
                                      onClick={() => handleUpdateStatus(r.id, 'assigned', `Forwarded to ${auth} for resolution.`, 'Chief Warden', { assignedAuthorityId: auth })} 
                                      className="px-5 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all"
                                    >
                                      Dispatch: {auth}
                                    </button>
                                  ))}
                               </div>
                            </div>
                          )}

                          {/* AUTHORITY: Taking Action & Intimating Admin */}
                          {user?.role === 'authority' && r.assignedAuthorityId === user.organization && (
                            <>
                              {r.status === 'assigned' && (
                                <button 
                                  onClick={() => handleUpdateStatus(r.id, 'investigating', 'Authority accepted tasking and started field work.', user.organization || 'Agency')} 
                                  className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs hover:bg-black transition-all"
                                >
                                  Begin Intervention Action
                                </button>
                              )}
                              {r.status === 'investigating' && (
                                <div className="space-y-4 w-full">
                                   <p className="text-[10px] font-black text-amber-600 uppercase">Intimate Admin of Solution:</p>
                                   <div className="flex flex-wrap gap-3">
                                      {FIELD_ACTIONS.map(act => (
                                        <button 
                                          key={act} 
                                          onClick={() => handleUpdateStatus(r.id, 'solved_by_authority', `Issue solved via ${act}. Notified Admin.`, user.organization || 'Agency', { actionTaken: act })} 
                                          className="px-5 py-3 bg-amber-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-amber-700 transition-all"
                                        >
                                          Execute {act} & Intimate Admin
                                        </button>
                                      ))}
                                   </div>
                                </div>
                              )}
                            </>
                          )}

                          {/* ADMIN: Phase 2 - Finalizing & Informing User */}
                          {user?.role === 'admin' && r.status === 'solved_by_authority' && (
                             <div className="w-full">
                               <button 
                                 onClick={() => handleUpdateStatus(r.id, 'resolved', 'Confirmed solution. Final notification sent to reporting user.', 'Chief Warden')} 
                                 className="w-full py-5 bg-emerald-600 text-white rounded-2xl font-black text-sm hover:bg-emerald-700 shadow-xl shadow-emerald-100 transition-all"
                               >
                                 Inform User & Close Incident
                               </button>
                             </div>
                          )}

                          {/* USER: Observational Role */}
                          {user?.role === 'user' && (
                            <div className="py-2">
                               <p className="text-xs font-bold text-slate-500 italic">
                                 {r.status === 'pending' && "Awaiting Admin review..."}
                                 {r.status === 'assigned' && "Admin forwarded this to local authorities."}
                                 {r.status === 'investigating' && "Authorities are active on the field."}
                                 {r.status === 'solved_by_authority' && "Authorities have finished. Admin is reviewing the fix."}
                                 {r.status === 'resolved' && "Incident closed. Thank you for your stewardship!"}
                               </p>
                            </div>
                          )}
                       </div>
                    </div>

                    {/* Timeline remains clear about who did what */}
                    <div className="space-y-6">
                      <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Incident Lifecycle</h4>
                      <div className="relative pl-8 space-y-6">
                         <div className="absolute left-1.5 top-2 bottom-2 w-0.5 bg-slate-100" />
                         {r.timeline.map((evt, idx) => (
                           <div key={idx} className="relative">
                              <div className={`absolute -left-[1.625rem] top-1 w-3 h-3 rounded-full border-4 border-white ${idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500') : 'bg-slate-200'}`} />
                              <div className="flex justify-between items-start">
                                 <div>
                                    <p className="text-sm font-black text-slate-900">{evt.message}</p>
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">{evt.actor}</p>
                                 </div>
                                 <span className="text-[9px] font-bold text-slate-300">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                              </div>
                           </div>
                         ))}
                      </div>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

