                               <p className="text-sm font-bold text-slate-700 italic">
                                 {r.status === 'pending' && "Command is reviewing your report for assignment..."}
                                 {r.status === 'assigned' && `Admin has forwarded your report to ${r.assignedAuthorityId}.`}
                                 {r.status === 'solved_by_authority' && "Authority has finished work. Admin is relaying the final details."}
                                 {r.status === 'resolved' && "Mission Complete. Your report led to successful environmental intervention."}
                               </p>
                            </div>
                          )}
                       </div>
                    </div>

                    {/* Operational Timeline */}
                    <div className="space-y-6">
                      <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Incident Lifecycle Log</h4>
                      <div className="relative pl-8 space-y-6">
                         <div className="absolute left-1.5 top-2 bottom-2 w-0.5 bg-slate-100" />
                         {r.timeline.map((evt, idx) => (
                           <div key={idx} className="relative">
                              <div className={`absolute -left-[1.625rem] top-1 w-3 h-3 rounded-full border-4 border-white ${idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500') : 'bg-slate-200'}`} />
                              <div className="flex justify-between items-start">
                                 <div>
                                    <p className="text-sm font-black text-slate-900">{evt.message}</p>
                                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Logged by: {evt.actor}</p>
                                 </div>
                                 <span className="text-[9px] font-bold text-slate-300">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                              </div>
                           </div>
                         ))}
                      </div>
                    </div>
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

