                      {user?.role === 'user' && (
                        <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100">
                           <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-3">Incident Monitoring Feedback</p>
