const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors());
// Fixed: Explicitly cast express.json middleware to any to resolve a type mismatch with app.use overloads.
// This is necessary when environment-specific types (e.g., NextHandleFunction) are not correctly identified as RequestHandlers.
