import React, { useState, useRef, useEffect } from 'react';
import { analyzeEnvironmentalImage } from '../services/geminiService';
import { AIAnalysisResult, IncidentType, Severity, Report } from '../types';

interface ReportWizardProps {
  onComplete: (report: Partial<Report>) => void;
}

const ReportWizard: React.FC<ReportWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AIAnalysisResult | null>(null);
  const [description, setDescription] = useState('');
  const [manualAddress, setManualAddress] = useState('');
  const [location, setLocation] = useState<{lat: number, lng: number, address: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        setLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          address: "Sector 42, Northern Ridge"
        });
        setManualAddress("Sector 42, Northern Ridge");
      });
    }
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setStep(2);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartAnalysis = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeEnvironmentalImage(base64Data);
      setAnalysis(result);
      setStep(3);
    } catch (err) {
      alert("AI analysis failed.");
      setStep(3);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSubmit = () => {
    onComplete({
      type: analysis?.detectedType || IncidentType.OTHER,
      severity: analysis?.severity || Severity.MEDIUM,
      description: description || analysis?.explanation || '',
      imageUrl: image || undefined,
      aiInsights: analysis?.explanation,
      location: { 
        lat: location?.lat || 0, 
        lng: location?.lng || 0, 
        address: manualAddress || "Manual Input Location" 
      },
      timestamp: new Date(),
    });
  };

  return (
    <div className="bg-white rounded-[3rem] p-10 shadow-2xl max-w-xl mx-auto border border-emerald-100 animate-slide-up">
      {step === 1 && (
        <div className="text-center py-10">
          <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
          <button onClick={() => fileInputRef.current?.click()} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl shadow-xl hover:bg-black transition-all">Select Media File</button>
        </div>
      )}
      {step === 2 && (
        <div className="text-center">
          <button disabled={analyzing} onClick={handleStartAnalysis} className="w-full bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg hover:bg-indigo-700">
            {analyzing ? "Synthesizing..." : "Deep Scan Image"}
          </button>
        </div>
      )}
      {step === 3 && (
        <div className="space-y-8">
          <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Description..." className="w-full bg-slate-50 border border-slate-100 rounded-3xl p-6 font-bold" />
          <button onClick={handleSubmit} className="w-full bg-emerald-600 text-white font-black py-5 rounded-[2rem]">Submit Secure Report</button>
        </div>
      )}
    </div>
  );
};

export default ReportWizard;

