            <svg className="w-5 h-5 absolute left-6 top-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" strokeWidth="2.5"/></svg>
          </div>

          <div className="relative group">
            <input 
              type="password" required value={password} onChange={(e) => setPassword(e.target.value)} 
              placeholder="Authorization Pin" 
              className="w-full px-8 py-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold focus:ring-4 outline-none transition-all pl-14" 
            />
            <svg className="w-5 h-5 absolute left-6 top-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" strokeWidth="2.5"/></svg>
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 text-[10px] font-black p-5 rounded-2xl border border-red-100 flex items-center gap-3 animate-shake">
              <svg className="w-5 h-5 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2"/></svg>
              {error}
            </div>
          )}

          <button 
            disabled={loading} 
            type="submit" 
            className={`w-full py-6 rounded-3xl font-black text-white shadow-2xl transition-all active:scale-[0.98] disabled:opacity-50 text-lg flex items-center justify-center gap-3 ${theme.btn}`}
          >
            {loading ? (
              <>
                <div className="w-5 h-5 border-3 border-white/30 border-t-white rounded-full animate-spin" />
                Validating...
              </>
            ) : (
              view === 'login' ? 'Establish Secure Link' : 'Initialize Profile'
            )}
          </button>
        </form>

        <div className="mt-8 pt-8 border-t border-slate-100 text-center space-y-4">
          <p className="text-slate-400 font-bold text-sm">
            {view === 'login' ? "New to the grid?" : "Already verified?"}
            <button 
              onClick={() => setView(view === 'login' ? 'register' : 'login')}
              className={`ml-2 font-black ${theme.text.replace('text-', 'text-')} hover:underline`}
            >
              {view === 'login' ? 'Request Enrollment' : 'Access Portal'}
            </button>
          </p>

          <div className="p-4 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
             <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Simulated Testing Credentials</p>
             <button 
               onClick={() => {
                 if (role === 'admin') { setEmail('admin@ecoguard.ai'); setPassword('admin'); }
                 else if (role === 'authority') { setEmail('forestry@agency.gov'); setPassword('forest'); }
                 else { setEmail('user@test.com'); setPassword('user'); }
               }}
               className="text-[10px] font-bold text-slate-600 hover:text-slate-900 underline decoration-slate-300 transition-all"
             >
               Auto-fill {role} debug token
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

