      if (r.id === id) {
        const newEvent: TimelineEvent = { 
          status: newStatus, 
          timestamp: new Date(), 
          message, 
          actor, 
          actionTaken: extraData?.actionTaken 
        };
        return { 
          ...r, 
          status: newStatus, 
          timeline: [...r.timeline, newEvent], 
          ...extraData 
        };
      }
      return r;
    }));
  };

  const severityOrder: Record<string, number> = {
    [Severity.LOW]: 1,
    [Severity.MEDIUM]: 2,
    [Severity.HIGH]: 3,
    [Severity.CRITICAL]: 4
  };

