    let filtered = user?.role === 'authority' 
      ? reports.filter(r => r.assignedAuthorityId === user.organization)
      : (user?.role === 'user' ? reports.filter(r => r.reporterId === user.id) : reports);

    // 2. User-defined filtering
    if (filterType !== 'All Types') {
      filtered = filtered.filter(r => r.type === filterType);
    }
    if (filterSeverity !== 'All Severities') {
      filtered = filtered.filter(r => r.severity === filterSeverity);
    }
    if (filterStatus !== 'All Statuses') {
      filtered = filtered.filter(r => r.status === filterStatus.toLowerCase().replace(' ', '_'));
    }

    // 3. Sorting
    return [...filtered].sort((a, b) => {
      if (sortBy === 'Newest') return b.timestamp.getTime() - a.timestamp.getTime();
      if (sortBy === 'Oldest') return a.timestamp.getTime() - b.timestamp.getTime();
      if (sortBy === 'Severity (High)') return severityOrder[b.severity] - severityOrder[a.severity];
      if (sortBy === 'Severity (Low)') return severityOrder[a.severity] - severityOrder[b.severity];
