            <button 
              onClick={() => { setFilterType('All Types'); setFilterSeverity('All Severities'); setFilterStatus('All Statuses'); setSortBy('Newest'); }}
              className="mt-5 px-6 py-2.5 border border-slate-200 rounded-xl text-[10px] font-black text-slate-400 hover:text-red-500 hover:border-red-100 transition-all uppercase tracking-widest"
