                         <span className="text-[10px] font-black text-slate-300">ID: {r.id}</span>
                      </div>

                      <p className="text-lg font-bold text-slate-700 mb-8 leading-relaxed italic">"{r.description}"</p>

                      {/* Role-Specific Actions */}
                      <div className="mb-8">
                        {user?.role === 'admin' && r.status === 'pending' && (
                          <div className="bg-indigo-50/50 p-6 rounded-3xl border border-indigo-100">
                            <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest mb-4">Admin Dispatch Protocol</p>
                            <div className="flex flex-wrap gap-2">
                              {AUTHORITIES.map(auth => (
                                <button 
                                  key={auth} 
                                  onClick={() => handleUpdateStatus(r.id, 'assigned', `Assigned to ${auth} for immediate inspection.`, 'Chief Warden', { assignedAuthorityId: auth })}
                                  className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg"
                                >
                                  Assign {auth}
                                </button>
                              ))}
                            </div>
                          </div>
                        )}

                        {user?.role === 'authority' && r.status === 'assigned' && (
                          <div className="bg-amber-50/50 p-6 rounded-3xl border border-amber-100">
                            <p className="text-[9px] font-black text-amber-600 uppercase tracking-widest mb-4">Agency Response Protocol</p>
                            <div className="flex flex-wrap gap-2">
                              {FIELD_ACTIONS.map(act => (
                                <button 
                                  key={act} 
                                  onClick={() => handleUpdateStatus(r.id, 'solved_by_authority', `Agency verified and executed: ${act}.`, user.organization || 'Agency', { actionTaken: act })}
                                  className="px-5 py-2.5 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-black transition-all shadow-lg"
                                >
                                  Mark as {act}
                                </button>
                              ))}
                            </div>
                          </div>
                        )}

                        {user?.role === 'user' && (
                          <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 flex items-center gap-4">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${r.status === 'resolved' ? 'bg-emerald-500' : 'bg-slate-300'}`}>
                              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M5 13l4 4L19 7" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
                            </div>
                            <div>
                               <p className="text-xs font-black text-slate-900">
                                 {r.status === 'pending' ? 'Command is reviewing evidence...' : 
                                  r.status === 'assigned' ? `Dispatched to ${r.assignedAuthorityId}` : 
                                  r.status === 'solved_by_authority' ? 'Agency action completed. Verifying...' : 'Issue fully resolved. Impact points awarded.'}
                               </p>
                               <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Network Update Sync: {new Date(r.timestamp).toLocaleDateString()}</p>
                            </div>
                          </div>
                        )}
                      </div>

                      {/* Timeline Mini-log */}
                      <div className="space-y-3">
                        <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Incident Timeline</h4>
                        <div className="space-y-3 relative pl-4 border-l-2 border-slate-50">
                          {r.timeline.slice(-2).map((evt, idx) => (
                            <div key={idx} className="relative">
                               <div className="absolute -left-[21px] top-1 w-2.5 h-2.5 rounded-full bg-white border-2 border-slate-200" />
                               <div className="flex justify-between items-center">
                                  <p className="text-[10px] font-bold text-slate-600">{evt.message}</p>
                                  <span className="text-[8px] font-black text-slate-300 uppercase">{evt.actor}</span>
                               </div>
                            </div>
                          ))}
                        </div>
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

