                        <div className="mb-10">

                          {/* 1. ADMIN ACTION: TRIAGE OR VERIFY */}
                          {user?.role === 'admin' && (
                            <div className="bg-indigo-50/50 p-8 rounded-[3rem] border border-indigo-100">
                              <div className="flex items-center gap-3 mb-6">
                                <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg">1</div>
                                <h4 className="text-xs font-black text-indigo-900 uppercase tracking-widest">Admin Command Actions</h4>
                              </div>

                              {r.status === 'pending' && (
