                                      onClick={() => handleUpdateStatus(r.id, 'assigned', 'Verification failed. Admin rejected solution. Incident remains open.', 'Chief Warden')}
                                      className="px-8 py-5 border-2 border-red-100 text-red-500 rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-red-50 transition-all"
                                    >
                                      Reject
                                    </button>
                                  </div>
                                </div>
                              )}

                              {r.status === 'assigned' && <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest pl-2">Waiting for Agency Response...</p>}
                              {r.status === 'resolved' && <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest pl-2">Case Fully Resolved.</p>}
                            </div>
                          )}

                          {/* 2. AGENCY ACTION: SOLVE & INTIMATE */}
                          {user?.role === 'authority' && r.assignedAuthorityId === user.organization && (
                            <div className="bg-amber-50/50 p-8 rounded-[3rem] border border-amber-100">
                              <div className="flex items-center gap-3 mb-6">
                                <div className="w-10 h-10 bg-amber-600 rounded-2xl flex items-center justify-center text-white font-black shadow-lg">2</div>
                                <h4 className="text-xs font-black text-amber-900 uppercase tracking-widest">Agency Response Panel</h4>
                              </div>

                              {r.status === 'assigned' && (
                                <div className="space-y-6">
                                  <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest mb-4">Execute Field Protocols: Solve & Notify Admin</p>
                                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                    {FIELD_ACTIONS.map(act => (
                                      <button 
                                        key={act} 
                                        onClick={() => handleUpdateStatus(r.id, 'solved_by_authority', `Agency executed protocol: ${act}. Solution intimated to Command.`, user.organization || 'Agency', { actionTaken: act })}
                                        className="px-6 py-4 bg-slate-900 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-black transition-all shadow-xl flex items-center gap-3"
                                      >
                                        <div className="w-2 h-2 rounded-full bg-amber-500" />
                                        {act}
                                      </button>
                                    ))}
                                  </div>
                                </div>
                              )}

                              {r.status === 'solved_by_authority' && (
                                <div className="flex items-center gap-4 bg-white p-6 rounded-3xl border border-amber-200">
                                  <div className="w-10 h-10 bg-blue-100 rounded-2xl flex items-center justify-center text-blue-600">
                                    <svg className="w-6 h-6 animate-spin" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2.5"/></svg>
                                  </div>
                                  <div>
                                    <p className="text-xs font-black text-blue-600 uppercase tracking-widest">Solution Intimated</p>
                                    <p className="text-[10px] font-bold text-slate-500 mt-1">Command is verifying the field solution.</p>
                                  </div>
                                </div>
                              )}

                              {r.status === 'resolved' && <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Incident Record Archived.</p>}
                            </div>
                          )}

                          {/* 3. USER INTERFACE: MONITOR STATUS */}
                          {user?.role === 'user' && (
                            <div className="bg-slate-50 p-10 rounded-[3rem] border border-slate-100">
                               <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-6">Sentinel Monitoring Feed</p>
                               <div className="flex flex-col sm:flex-row items-center gap-8">
                                 <div className={`w-24 h-24 rounded-[2rem] flex items-center justify-center text-white shadow-2xl transition-all duration-700 ${
                                   r.status === 'resolved' ? 'bg-emerald-500 scale-110' : 
                                   r.status === 'solved_by_authority' ? 'bg-blue-500 animate-pulse' : 'bg-slate-300'
                                 }`}>
                                   {r.status === 'resolved' ? (
                                     <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="3"/></svg>
                                   ) : (
                                     <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="3"/></svg>
                                   )}
                                 </div>
                                 <div className="text-center sm:text-left">
                                   <p className="text-2xl font-black text-slate-900 tracking-tight mb-2">
                                     {r.status === 'pending' && "Reviewing your report..."}
                                     {r.status === 'assigned' && `Forwarded to ${r.assignedAuthorityId}.`}
                                     {r.status === 'solved_by_authority' && "Field action complete. Validating..."}
                                     {r.status === 'resolved' && "Issue Solved! +100 Points Awarded."}
                                   </p>
                                   <div className="flex items-center gap-3 justify-center sm:justify-start">
                                      <div className={`w-2 h-2 rounded-full ${r.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500 animate-ping'}`} />
                                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Operational Sync: {new Date(r.timestamp).toLocaleDateString()}</p>
                                   </div>
                                 </div>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>

                      {/* Unified Timeline Footer */}
                      <div className="pt-10 border-t border-slate-50">
                        <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em] mb-6">Incident Lifecycle Journal</h4>
                        <div className="space-y-6 relative pl-8">
                           <div className="absolute left-[3px] top-2 bottom-2 w-[2px] bg-slate-100" />
                           {r.timeline.map((evt, idx) => (
                             <div key={idx} className="relative">
                                <div className={`absolute -left-[32px] top-1.5 w-3.5 h-3.5 rounded-full border-4 border-white shadow-sm ${
                                  idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-indigo-600') : 'bg-slate-200'
                                }`} />
                                <div className="flex justify-between items-start gap-4">
                                   <div>
                                      <p className="text-sm font-bold text-slate-800">{evt.message}</p>
                                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Originator: <span className="text-slate-600">{evt.actor}</span></p>
                                   </div>
                                   <span className="text-[10px] font-bold text-slate-300 whitespace-nowrap">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                </div>
                             </div>
                           ))}
                        </div>
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

export default App;

