  const handleAuthSuccess = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    setIsAuthenticated(true);
  };

  const handleUpdateStatus = (id: string, newStatus: ReportStatus, message: string, actor: string, extraData?: any) => {
    setReports(prev => prev.map(r => {
      if (r.id === id) {
        const newEvent: TimelineEvent = { 
          status: newStatus, 
          timestamp: new Date(), 
          message, 
          actor, 
          actionTaken: extraData?.actionTaken 
        };
        return { 
          ...r, 
          status: newStatus, 
          timeline: [...r.timeline, newEvent], 
          ...extraData 
        };
      }
      return r;
    }));
  };

  // Strictly filter reports based on the specialized UI requirements for each role
  const visibleReports = useMemo(() => {
    if (!user) return [];

    switch (user.role) {
      case 'admin':
        // Admin sees EVERYTHING
        return reports;
      case 'authority':
        // Agency ONLY sees what is assigned to their specific organization
        return reports.filter(r => r.assignedAuthorityId === user.organization);
      case 'user':
        // Citizen ONLY sees their personal reports
        return reports.filter(r => r.reporterId === user.id);
      default:
        return [];
    }
  }, [reports, user]);

  // Logic to calculate pending notifications/actions for badges
  const alertsCount = useMemo(() => {
    if (user?.role === 'admin') {
      // Admin alerted on new reports (pending) and agency completions (solved_by_authority)
      return reports.filter(r => r.status === 'pending' || r.status === 'solved_by_authority').length;
    }
    if (user?.role === 'authority') {
      // Agency alerted on tasks assigned to them
      return reports.filter(r => r.status === 'assigned' && r.assignedAuthorityId === user.organization).length;
    }
    return 0;
  }, [reports, user]);

  if (!isAuthenticated) return <Login onLoginSuccess={handleAuthSuccess} />;

  const themeColor = user?.role === 'admin' ? 'indigo' : user?.role === 'authority' ? 'amber' : 'emerald';

  return (
    <Layout user={user!} onLogout={() => setIsAuthenticated(false)} activeTab={activeTab} setActiveTab={setActiveTab}>

      {activeTab === 'dashboard' && <Dashboard reports={reports} user={user!} onNewReport={() => setActiveTab('report')} onNavigate={(t) => setActiveTab(t)} />}

      {activeTab === 'report' && user?.role === 'user' && (
        <ReportWizard onComplete={(data) => {
          const nr: Report = { 
            ...data, 
            id: `R-${Math.floor(Math.random() * 900) + 100}`, 
            status: 'pending', 
            reporterId: user!.id, 
            timeline: [{ 
              status: 'pending', 
              timestamp: new Date(), 
              message: 'Incident reported. Awaiting Admin verification.', 
              actor: user!.name 
            }] 
          } as Report;
          setReports([nr, ...reports]);
          setActiveTab('reports');
        }} />
      )}

      {activeTab === 'reports' && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">

          {/* Unified Role-Specific Command Bar */}
