            user?.role === 'admin' ? 'bg-indigo-900 text-white border-indigo-700' : 
            user?.role === 'authority' ? 'bg-amber-900 text-white border-amber-700' : 'bg-white border-slate-100'
          }`}>
             <div className="flex items-center gap-6">
                <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-xl ${
