                             <div key={idx} className="relative">
                                <div className={`absolute -left-[40px] top-1.5 w-4 h-4 rounded-full border-4 border-white shadow-sm ${
                                  idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-indigo-600') : 'bg-slate-200'
                                }`} />
                                <div className="flex justify-between items-start gap-10">
                                   <div>
                                      <p className="text-sm font-black text-slate-800 tracking-tight">{evt.message}</p>
                                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1.5">Action By: <span className="text-slate-900">{evt.actor}</span></p>
                                   </div>
                                   <span className="text-[10px] font-bold text-slate-300 whitespace-nowrap bg-slate-50 px-2 py-1 rounded-md">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                </div>
                             </div>
                           ))}
                        </div>
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService.ts';
import { User, UserRole } from '../types.ts';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

type AuthView = 'selector' | 'login' | 'register';

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [view, setView] = useState<AuthView>('selector');
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [org, setOrg] = useState(AUTHORITIES[0]);

  const resetForms = () => {
    setEmail('');
    setPassword('');
    setName('');
    setError('');
  };

  const selectPortal = (selectedRole: UserRole) => {
    setRole(selectedRole);
    setView('login');
    resetForms();
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      if (view === 'register') {
        const newUser = await registerUser(name, email, role, role === 'authority' ? org : undefined);
        onLoginSuccess(newUser);
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err: any) {
      setError(err.message || "Authentication failed.");
      setLoading(false);
    }
  };

  const getTheme = () => {
    switch(role) {
      case 'admin': return { 
        primary: 'indigo', 
