        text: 'text-amber-400', 
        btn: 'bg-amber-600 hover:bg-amber-500', 
        accent: 'amber-500/10',
        label: 'Agency Response'
      };
      default: return { 
        primary: 'emerald', 
        bg: 'bg-[#061e1a]', 
        text: 'text-emerald-400', 
        btn: 'bg-emerald-600 hover:bg-emerald-500', 
        accent: 'emerald-500/10',
        label: 'User Portal'
