          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <h1 className="text-5xl md:text-7xl font-black text-white tracking-tighter">
              EcoGuardian<span className="text-emerald-500">AI</span>
            </h1>
            <p className="text-slate-400 text-lg md:text-xl font-medium tracking-wide max-w-2xl mx-auto">
              Choose your secure gateway to the environmental sentinel network.
            </p>
          </div>

          <div className="grid md:grid-cols-3 gap-8 px-4">
            {/* User Portal */}
            <button 
              onClick={() => selectPortal('user')}
              className="group relative bg-[#0f172a]/40 backdrop-blur-3xl border border-white/5 p-12 rounded-[4rem] text-left hover:bg-emerald-500/5 hover:border-emerald-500/40 transition-all duration-500 hover:-translate-y-3 shadow-2xl"
            >
              <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center text-emerald-400 mb-10 group-hover:scale-110 transition-transform shadow-inner">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2"/></svg>
              </div>
              <h3 className="text-3xl font-black text-white mb-3">User</h3>
              <p className="text-slate-400 text-base leading-relaxed mb-8">Report environmental incidents, track wildlife sightings, and contribute to conservation data.</p>
              <div className="text-emerald-500 text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                Access Network <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17 8l4 4m0 0l-4 4m4-4H3" strokeWidth="2.5"/></svg>
              </div>
            </button>

            {/* Admin Portal */}
            <button 
              onClick={() => selectPortal('admin')}
