            >
              <div className="w-20 h-20 bg-amber-500/10 rounded-3xl flex items-center justify-center text-amber-400 mb-10 group-hover:scale-110 transition-transform shadow-inner">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" strokeWidth="2"/></svg>
              </div>
              <h3 className="text-3xl font-black text-white mb-3">Agency</h3>
              <p className="text-slate-400 text-base leading-relaxed mb-8">Operational board for field units to execute interventions and intimate resolution status to admin.</p>
              <div className="text-amber-500 text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-2">
                Response Hub <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17 8l4 4m0 0l-4 4m4-4H3" strokeWidth="2.5"/></svg>
              </div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen transition-colors duration-1000 ${theme.bg} flex flex-col items-center justify-center p-6 relative overflow-hidden`}>
