      <div className="relative z-10 w-full max-w-lg bg-white/95 backdrop-blur-3xl rounded-[3.5rem] p-12 shadow-2xl border border-white/20 animate-slide-up">
        <button 
          onClick={() => setView('selector')}
          className="absolute top-8 left-8 text-slate-400 hover:text-slate-900 transition-colors flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 19l-7-7m0 0l7-7m-7 7h18" strokeWidth="3"/></svg>
