  const visibleReports = useMemo(() => {
    if (!user) return [];
    switch (user.role) {
      case 'admin': return reports;
      case 'authority': return reports.filter(r => r.assignedAuthorityId === user.organization);
      case 'user': return reports.filter(r => r.reporterId === user.id);
      default: return [];
