                                     {AUTHORITIES.map(auth => (
                                       <button key={auth} 
                                         onClick={() => handleUpdateStatus(r.id, 'assigned', `Command dispatched ${auth}.`, 'Chief Warden', { assignedAuthorityId: auth })}
                                         className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-900/20"
                                       >Deploy {auth}</button>
                                     ))}
                                   </div>
                                 </div>
                               )}

                               {r.status === 'solved_by_authority' && (
                                 <div className="space-y-8">
                                   <div className="bg-white/5 p-8 rounded-[2rem] border border-indigo-500/20">
                                      <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-4">Agency Resolution Summary:</p>
                                      <p className="text-lg font-bold text-slate-100 italic">"{r.resolutionDetails || 'No manual report provided.'}"</p>
                                   </div>
                                   <div className="flex gap-4">
                                      <button 
                                        onClick={() => handleUpdateStatus(r.id, 'resolved', 'Command verified and closed the incident. User notified.', 'Chief Warden')}
                                        className="flex-1 py-5 bg-emerald-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-emerald-500 shadow-2xl shadow-emerald-900/40 transition-all flex items-center justify-center gap-3"
                                      >Verify & Notify User</button>
                                      <button 
                                        onClick={() => handleUpdateStatus(r.id, 'assigned', 'Command rejected agency solution. Re-opening task.', 'Chief Warden')}
                                        className="px-10 py-5 bg-red-500/10 text-red-400 rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-red-500/20 transition-all border border-red-500/20"
                                      >Reject Action</button>
                                   </div>
                                 </div>
                               )}
                               {r.status === 'assigned' && <p className="text-[10px] font-black text-amber-500 uppercase tracking-[0.2em] pl-4">Agency unit currently mobilized...</p>}
                            </div>
                          )}

                          {/* AGENCY: Manual Resolution Form */}
                          {user?.role === 'authority' && (
                            <div className="bg-amber-500/5 p-10 rounded-[3rem] border border-amber-500/10 space-y-8">
                               <div className="flex items-center gap-4">
                                  <div className="w-10 h-10 bg-amber-600 rounded-2xl flex items-center justify-center text-white font-black">02</div>
                                  <h4 className="text-[10px] font-black text-amber-400 uppercase tracking-[0.3em]">Action Protocol</h4>
                               </div>

                               {r.status === 'assigned' && (
                                 <div className="space-y-6">
                                   <p className="text-sm font-bold text-slate-400">Submit a manual report of the intervention to intimate Command:</p>
                                   <textarea 
                                      value={agencyActionText}
                                      onChange={(e) => setAgencyActionText(e.target.value)}
                                      placeholder="Describe the physical intervention performed by your unit..."
                                      className="w-full bg-white/5 border border-white/10 rounded-3xl p-6 font-bold text-white focus:ring-4 focus:ring-amber-500/10 outline-none transition-all min-h-[140px]"
                                   />
                                   <button 
                                      disabled={!agencyActionText.trim()}
                                      onClick={() => handleUpdateStatus(r.id, 'solved_by_authority', `Agency reported solution: ${agencyActionText}`, user.organization || 'Agency', { resolutionDetails: agencyActionText })}
                                      className="w-full py-5 bg-amber-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-amber-500 disabled:opacity-30 transition-all shadow-2xl shadow-amber-900/40"
                                   >Intimate Resolution to Command</button>
                                 </div>
                               )}

                               {r.status === 'solved_by_authority' && (
                                 <div className="flex items-center gap-5 bg-white/5 p-8 rounded-[2rem] border border-blue-500/20 animate-pulse">
                                    <div className="w-12 h-12 bg-blue-500/10 rounded-2xl flex items-center justify-center text-blue-400">
                                       <svg className="w-8 h-8 animate-spin" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="3"/></svg>
                                    </div>
                                    <div>
                                       <p className="text-sm font-black text-blue-400 uppercase tracking-widest">Intimation Sent</p>
                                       <p className="text-xs font-bold text-slate-500 mt-1">Global Command is currently verifying your manual intervention report.</p>
                                    </div>
                                 </div>
                               )}
                            </div>
                          )}

                          {/* USER: Real-time status tracker */}
                          {user?.role === 'user' && (
                            <div className="bg-emerald-500/5 p-12 rounded-[3rem] border border-emerald-500/10 flex flex-col md:flex-row items-center gap-10">
                               <div className={`w-28 h-28 rounded-[2rem] flex items-center justify-center text-white shadow-3xl transition-all duration-1000 ${
                                 r.status === 'resolved' ? 'bg-emerald-500 shadow-emerald-500/40 scale-110' : 
                                 r.status === 'solved_by_authority' ? 'bg-blue-500 animate-pulse' : 'bg-slate-700'
                               }`}>
                                  {r.status === 'resolved' ? <svg className="w-14 h-14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M5 13l4 4L19 7" strokeWidth="4"/></svg> : <svg className="w-14 h-14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="4"/></svg>}
                               </div>
                               <div className="flex-1 text-center md:text-left">
                                  <h4 className="text-3xl font-black text-white tracking-tighter mb-2">
                                    {r.status === 'pending' && "Reviewing Evidence..."}
                                    {r.status === 'assigned' && "Deploying Agency..."}
                                    {r.status === 'solved_by_authority' && "Final Verification..."}
                                    {r.status === 'resolved' && "Incident Solved!"}
                                  </h4>
                                  <p className="text-slate-400 font-bold leading-relaxed mb-4">
                                    {r.status === 'pending' && "Global Command is verifying your report for immediate dispatch."}
                                    {r.status === 'assigned' && `The ${r.assignedAuthorityId} is performing a field intervention.`}
                                    {r.status === 'solved_by_authority' && "Agency action complete. Command is validating the resolution."}
                                    {r.status === 'resolved' && "The site has been restored. 100 Impact Points have been credited to your profile."}
                                  </p>
                                  <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/5 border border-white/5 rounded-xl text-[9px] font-black text-slate-500 uppercase tracking-widest">Sector Sync: {new Date(r.timestamp).toLocaleDateString()}</div>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>

                      {/* Operational Journal */}
                      <div className="mt-12 pt-10 border-t border-white/5">
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em] mb-8">Incident Journal Log</h4>
                        <div className="space-y-8 relative pl-10">
                           <div className="absolute left-[5px] top-2 bottom-2 w-0.5 bg-white/5" />
                           {r.timeline.map((evt, idx) => (
                             <div key={idx} className="relative">
                                <div className={`absolute -left-[40px] top-1.5 w-4 h-4 rounded-full border-4 border-[#0f172a] shadow-sm ${
                                  idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-indigo-500') : 'bg-slate-700'
                                }`} />
                                <div className="flex justify-between items-start">
                                   <div>
                                      <p className="text-sm font-black text-white tracking-tight">{evt.message}</p>
                                      <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Origin: <span className="text-slate-300">{evt.actor}</span></p>
                                   </div>
                                   <span className="text-[10px] font-bold text-slate-500 bg-white/5 px-2 py-1 rounded-lg">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                </div>
                             </div>
                           ))}
                        </div>
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService.ts';
import { User, UserRole } from '../types.ts';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

interface LoginProps {
  onLoginSuccess: (user: User) => void;
}

type AuthView = 'selector' | 'login' | 'register';

const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [view, setView] = useState<AuthView>('selector');
  const [role, setRole] = useState<UserRole>('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [org, setOrg] = useState(AUTHORITIES[0]);

  const resetForms = () => {
    setEmail('');
    setPassword('');
    setName('');
    setError('');
  };

  const selectPortal = (selectedRole: UserRole) => {
    setRole(selectedRole);
    setView('login');
    resetForms();
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      if (view === 'register') {
        const newUser = await registerUser(name, email, role, role === 'authority' ? org : undefined);
        onLoginSuccess(newUser);
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err: any) {
      setError(err.message || "Authentication failed.");
      setLoading(false);
    }
  };

  const getTheme = () => {
    switch(role) {
      case 'admin': return { 
        primary: 'indigo', 
        bg: 'bg-[#0f172a]', 
        text: 'text-indigo-400', 
        btn: 'bg-indigo-600 hover:bg-indigo-500', 
        accent: 'indigo-500/10',
        label: 'Global Command'
      };
      case 'authority': return { 
        primary: 'amber', 
        bg: 'bg-[#1a1408]', 
        text: 'text-amber-400', 
        btn: 'bg-amber-600 hover:bg-amber-500', 
        accent: 'amber-500/10',
        label: 'Agency Board'
      };
      default: return { 
        primary: 'emerald', 
        bg: 'bg-[#061e1a]', 
        text: 'text-emerald-400', 
        btn: 'bg-emerald-600 hover:bg-emerald-500', 
        accent: 'emerald-500/10',
        label: 'Citizen Portal'
      };
    }
  };

  const theme = getTheme();

  if (view === 'selector') {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full opacity-30 pointer-events-none">
          <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-emerald-500/10 rounded-full blur-[140px]" />
          <div className="absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] bg-indigo-500/10 rounded-full blur-[140px]" />
        </div>

        <div className="relative z-10 w-full max-w-7xl text-center space-y-16">
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter">
              Sentinel<span className="text-emerald-500">AI</span>
            </h1>
            <p className="text-slate-400 text-lg md:text-2xl font-medium tracking-wide max-w-2xl mx-auto opacity-70">
              Select your authorization node to enter the environmental grid.
            </p>
          </div>

          <div className="grid md:grid-cols-3 gap-10 px-4">
            {/* User Portal */}
            <button 
              onClick={() => selectPortal('user')}
              className="group relative bg-[#0f172a] border border-white/5 p-12 rounded-[4rem] text-left hover:bg-[#131d36] hover:border-emerald-500/30 transition-all duration-500 hover:-translate-y-4 shadow-3xl"
            >
              <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center text-emerald-400 mb-10 group-hover:scale-110 transition-transform border border-emerald-500/20">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" strokeWidth="2"/></svg>
              </div>
              <h3 className="text-4xl font-black text-white mb-4 tracking-tight">Citizen Portal</h3>
              <p className="text-slate-400 text-lg leading-relaxed mb-10 opacity-60">Report land damage, injured wildlife, and illegal logging. Earn environmental impact points.</p>
              <div className="text-emerald-500 text-xs font-black uppercase tracking-[0.3em] flex items-center gap-3 group-hover:gap-5 transition-all">
                ACCESS SENTINEL NETWORK <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17 8l4 4m0 0l-4 4m4-4H3" strokeWidth="3"/></svg>
              </div>
            </button>

            {/* Agency Portal */}
            <button 
              onClick={() => selectPortal('authority')}
              className="group relative bg-[#0f172a] border border-white/5 p-12 rounded-[4rem] text-left hover:bg-[#1a1408] hover:border-amber-500/30 transition-all duration-500 hover:-translate-y-4 shadow-3xl"
            >
              <div className="w-20 h-20 bg-amber-500/10 rounded-3xl flex items-center justify-center text-amber-400 mb-10 group-hover:scale-110 transition-transform border border-amber-500/20">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2"/></svg>
              </div>
              <h3 className="text-4xl font-black text-white mb-4 tracking-tight">Agency Board</h3>
              <p className="text-slate-400 text-lg leading-relaxed mb-10 opacity-60">Operational interface for Forestry, Wildlife, and Parks units. Manage field interventions.</p>
              <div className="text-amber-500 text-xs font-black uppercase tracking-[0.3em] flex items-center gap-3 group-hover:gap-5 transition-all">
                RESPONSE PROTOCOLS <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17 8l4 4m0 0l-4 4m4-4H3" strokeWidth="3"/></svg>
              </div>
            </button>

            {/* Admin Portal */}
            <button 
              onClick={() => selectPortal('admin')}
              className="group relative bg-[#0f172a] border border-white/5 p-12 rounded-[4rem] text-left hover:bg-[#131d36] hover:border-indigo-500/30 transition-all duration-500 hover:-translate-y-4 shadow-3xl"
            >
              <div className="w-20 h-20 bg-indigo-500/10 rounded-3xl flex items-center justify-center text-indigo-400 mb-10 group-hover:scale-110 transition-transform border border-indigo-500/20">
                <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" strokeWidth="2"/></svg>
              </div>
              <h3 className="text-4xl font-black text-white mb-4 tracking-tight">Global Command</h3>
              <p className="text-slate-400 text-lg leading-relaxed mb-10 opacity-60">System dispatch and incident verification. High-level monitoring and analytics.</p>
              <div className="text-indigo-500 text-xs font-black uppercase tracking-[0.3em] flex items-center gap-3 group-hover:gap-5 transition-all">
                SYSTEM AUTHORIZATION <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17 8l4 4m0 0l-4 4m4-4H3" strokeWidth="3"/></svg>
              </div>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen transition-all duration-1000 ${theme.bg} flex flex-col items-center justify-center p-6 relative overflow-hidden`}>
      <div className="absolute inset-0 bg-[#020617]/50 pointer-events-none" />

      <div className="relative z-10 w-full max-w-xl bg-white rounded-[4rem] p-16 shadow-[0_50px_100px_rgba(0,0,0,0.5)] animate-slide-up">
        <button onClick={() => setView('selector')} className="absolute top-10 left-10 text-slate-400 hover:text-slate-900 transition-colors flex items-center gap-2 text-[10px] font-black uppercase tracking-widest">
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M10 19l-7-7m0 0l7-7m-7 7h18" strokeWidth="3"/></svg>
          Return to Hub
        </button>

        <div className="text-center mb-12 mt-4">
          <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${theme.text} mb-4`}>{theme.label} Node</p>
          <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
            {view === 'login' ? 'Authorization' : 'Grid Register'}
          </h2>
        </div>

        <form onSubmit={handleAuth} className="space-y-6">
          {view === 'register' && (
            <div className="space-y-6">
              <input type="text" required value={name} onChange={(e) => setName(e.target.value)} placeholder="Personnel Name" 
                className="w-full px-8 py-5 bg-slate-50 border border-slate-100 rounded-3xl font-bold focus:ring-4 outline-none transition-all" />
              {role === 'authority' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-4">Agency Designation</label>
                  <select value={org} onChange={(e) => setOrg(e.target.value)} className="w-full px-8 py-5 bg-slate-50 border border-slate-100 rounded-3xl font-bold focus:ring-4 outline-none transition-all appearance-none">
                    {AUTHORITIES.map(a => <option key={a} value={a}>{a}</option>)}
                  </select>
                </div>
              )}
            </div>
          )}

          <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Official Token (Email)" 
            className="w-full px-8 py-5 bg-slate-50 border border-slate-100 rounded-3xl font-bold focus:ring-4 outline-none transition-all" />

          <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Access Key" 
            className="w-full px-8 py-5 bg-slate-50 border border-slate-100 rounded-3xl font-bold focus:ring-4 outline-none transition-all" />

          {error && <div className="bg-red-50 text-red-600 text-[10px] font-black p-6 rounded-3xl border border-red-100">{error}</div>}

          <button disabled={loading} type="submit" className={`w-full py-6 rounded-[2rem] font-black text-white shadow-2xl transition-all active:scale-95 disabled:opacity-50 text-xl ${theme.btn}`}>
            {loading ? 'Decrypting...' : view === 'login' ? 'Establish Link' : 'Initialize Node'}
          </button>
        </form>

        <div className="mt-12 pt-10 border-t border-slate-50 text-center space-y-6">
          <p className="text-slate-400 font-bold text-sm">
            {view === 'login' ? "Node not registered?" : "Already recognized?"}
            <button onClick={() => setView(view === 'login' ? 'register' : 'login')} className={`ml-2 font-black ${theme.text} hover:underline`}>
              {view === 'login' ? 'Apply Now' : 'Access Node'}
            </button>
          </p>
          <div className="p-6 bg-slate-50 rounded-3xl border border-dashed border-slate-200">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Operational Tokens</p>
             <button onClick={() => {
                 if (role === 'admin') { setEmail('admin@ecoguard.ai'); setPassword('admin'); }
                 else if (role === 'authority') { setEmail('forestry@agency.gov'); setPassword('forest'); }
                 else { setEmail('user@test.com'); setPassword('user'); }
               }} className="text-[11px] font-black text-slate-800 hover:text-emerald-600 underline transition-all">
               Inject {role} Credentials
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

export enum IncidentType {
  LAND_DAMAGE = 'Land Damage',
  ILLEGAL_LOGGING = 'Illegal Logging',
  INJURED_WILDLIFE = 'Injured Wildlife',
  ROAD_ACCIDENT = 'Animal Road Accident',
  POLLUTION = 'Pollution',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export type UserRole = 'user' | 'admin' | 'authority';

export type ReportStatus = 'pending' | 'verified' | 'assigned' | 'investigating' | 'solved_by_authority' | 'resolved' | 'rejected';

export interface TimelineEvent {
  status: ReportStatus;
  timestamp: Date;
  message: string;
  actor: string;
  actionTaken?: string;
}

export interface Report {
  id: string;
  type: IncidentType;
  severity: Severity;
  description: string;
  location: {
    lat: number;
    lng: number;
    address?: string;
  };
  timestamp: Date;
  imageUrl?: string;
  status: ReportStatus;
  reporterId: string;
  assignedAuthorityId?: string; 
  aiInsights?: string;
  timeline: TimelineEvent[];
  resolutionDetails?: string;
  resolvedImageUrl?: string;
  resolvedTimestamp?: Date;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  points: number;
  reportsCount: number;
  avatar?: string;
  organization?: string;
}

export interface AIAnalysisResult {
  detectedType: IncidentType;
  severity: Severity;
  explanation: string;
  recommendedAction: string;
}

export interface EnvironmentalResource {
  id: string;
  title: string;
  content: string;
  category: 'note' | 'wildlife' | 'link';
  url?: string;
  icon?: string;
}

import mongoose from 'mongoose';

const timelineEventSchema = new mongoose.Schema({
  status: String,
  timestamp: { type: Date, default: Date.now },
  message: String,
  actor: String,
  actionTaken: String
});

const reportSchema = new mongoose.Schema({
  type: { type: String, required: true },
  severity: { type: String, required: true },
  description: String,
  location: {
    lat: Number,
    lng: Number,
    address: String
  },
  timestamp: { type: Date, default: Date.now },
  imageUrl: String,
  status: { type: String, default: 'pending' },
  reporterId: String,
  assignedAuthorityId: String,
  aiInsights: String,
  timeline: [timelineEventSchema],
  resolutionDetails: String,
  resolvedImageUrl: String,
  resolvedTimestamp: Date
});

export default mongoose.model('Report', reportSchema);

