              </div>
            ) : (
              visibleReports.map(r => (
                <div key={r.id} className="bg-[#0f172a] rounded-[4rem] border border-white/5 shadow-3xl overflow-hidden flex flex-col group transition-all duration-500 hover:border-emerald-500/20">

