                  user?.role === 'admin' ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' : 
                  user?.role === 'authority' ? 'bg-amber-600/20 text-amber-400 border border-amber-500/30' : 
                  'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30'
                }`}>
                   <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      {user?.role === 'admin' ? <path d="M12 21l-8-4.5v-9L12 3l8 4.5v9l-8 4.5z" strokeWidth="2"/> : 
                       user?.role === 'authority' ? <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2"/> :
                       <path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2"/>}
                   </svg>
                </div>
                <div>
                  <h2 className="text-4xl font-black text-white tracking-tighter">
                    {user?.role === 'admin' ? 'Global Command' : 
                     user?.role === 'authority' ? 'Agency Board' : 'Citizen Portal'}
                  </h2>
                  <p className="text-slate-400 font-medium mt-1">
                    {user?.role === 'admin' ? 'Incident triage and final verification nexus.' : 
                     user?.role === 'authority' ? `Operational interface for ${user.organization}.` : 'Secure channel for environmental reporting.'}
                  </p>
                </div>
             </div>
          </div>

          <div className="grid gap-16">
            {visibleReports.length === 0 ? (
              <div className="text-center py-24 bg-[#0f172a]/40 rounded-[4rem] border border-dashed border-white/5">
                 <p className="font-black text-slate-500 uppercase tracking-widest text-xl">No Active Reports in Sector</p>
              </div>
            ) : (
              visibleReports.map(r => (
                <div key={r.id} className="bg-[#0f172a] rounded-[4rem] border border-white/5 shadow-3xl overflow-hidden flex flex-col group transition-all duration-500 hover:border-emerald-500/20">

                   {/* Main Header Information */}
                   <div className="p-12 pb-0 flex flex-col md:flex-row justify-between gap-8">
                      <div className="space-y-4">
                        <div className="flex items-center gap-4">
                           <span className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest text-white ${
                             r.severity === Severity.CRITICAL ? 'bg-red-500 shadow-[0_0_20px_rgba(239,68,68,0.4)]' : 
                             r.severity === Severity.HIGH ? 'bg-orange-500' : 'bg-emerald-500'
                           }`}>{r.type}</span>
                           <div className={`w-3.5 h-3.5 rounded-full shadow-lg ${
                             r.status === 'resolved' ? 'bg-emerald-500' : 
                             r.status === 'solved_by_authority' ? 'bg-blue-500 animate-pulse' : 
                             r.status === 'assigned' ? 'bg-amber-500' : 'bg-slate-400'
                           }`} />
                           <p className="text-xs font-black text-slate-400 uppercase tracking-widest">
                             Status: <span className="text-white">{r.status.replace('_', ' ')}</span>
                           </p>
                        </div>

                        {/* Explicit Address Display */}
                        <div className="flex items-center gap-3 text-emerald-400">
                           <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" strokeWidth="2"/><path d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
                           <h3 className="text-white text-3xl font-black tracking-tighter leading-none">{r.location.address}</h3>
                        </div>

                        <p className="text-xl font-bold text-slate-400 max-w-2xl italic leading-relaxed border-l-4 border-white/10 pl-6">"{r.description}"</p>
                      </div>
                      <div className="text-right">
                         <div className="text-[10px] font-black text-slate-500 tracking-[0.2em] bg-white/5 px-4 py-2 rounded-xl border border-white/5 inline-block">ID: {r.id}</div>
                         <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mt-4">Reported: {new Date(r.timestamp).toLocaleDateString()}</p>
                      </div>
                   </div>

                   {/* Visual Evidence Area */}
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-12">
                      <div className="space-y-4">
                         <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Incident Evidence</p>
                         <div className="aspect-video relative rounded-[2.5rem] overflow-hidden border border-white/5">
                            <img src={r.imageUrl} className="w-full h-full object-cover" alt="Before" />
                            <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a] via-transparent to-transparent opacity-60" />
                            <div className="absolute bottom-6 left-8 bg-black/40 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10 text-[9px] font-black text-white uppercase tracking-widest">Initial Report</div>
                         </div>
                      </div>

                      {(r.status === 'solved_by_authority' || r.status === 'resolved') ? (
                        <div className="space-y-4 animate-in fade-in zoom-in duration-700">
                           <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest pl-2">Field Resolution Proof</p>
                           <div className="aspect-video relative rounded-[2.5rem] overflow-hidden border border-emerald-500/20">
                              <img src={r.resolvedImageUrl} className="w-full h-full object-cover" alt="After" />
                              <div className="absolute inset-0 bg-gradient-to-t from-[#0f172a] via-transparent to-transparent opacity-60" />
                              <div className="absolute bottom-6 left-8 bg-emerald-600/60 backdrop-blur-md px-4 py-2 rounded-xl border border-white/10 text-[9px] font-black text-white uppercase tracking-widest">Resolution Proof</div>
                           </div>
                        </div>
                      ) : (
                        <div className="flex items-center justify-center bg-white/5 rounded-[2.5rem] border border-dashed border-white/10">
                           <p className="text-slate-600 font-black text-xs uppercase tracking-widest">Awaiting Field Action...</p>
                        </div>
                      )}
                   </div>

                   {/* Protocol & Action Area */}
                   <div className="px-12 pb-12">
                      {/* ADMIN PROTOCOL */}
                      {user?.role === 'admin' && (
                        <div className="bg-indigo-500/5 p-10 rounded-[3rem] border border-indigo-500/10 space-y-8">
                           {r.status === 'pending' && (
                             <div className="space-y-6">
                               <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Dispatch Protocol: Assign Specialized Unit</p>
                               <div className="flex flex-wrap gap-3">
                                 {AUTHORITIES.map(auth => (
                                   <button key={auth} 
                                     onClick={() => handleUpdateStatus(r.id, 'assigned', `Admin triaged and deployed ${auth}.`, 'Chief Warden', { assignedAuthorityId: auth })}
                                     className="px-8 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-900/40"
                                   >Deploy {auth}</button>
                                 ))}
                               </div>
                             </div>
                           )}

                           {r.status === 'solved_by_authority' && (
                             <div className="space-y-8">
                               <div className="bg-white/5 p-8 rounded-[2rem] border border-indigo-500/20">
                                  <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-4">Agency Closure Report:</p>
                                  <p className="text-lg font-bold text-slate-100 italic">"{r.resolutionDetails}"</p>
                               </div>
                               <div className="flex gap-4">
                                  <button 
                                    onClick={() => handleUpdateStatus(r.id, 'resolved', 'Admin verified the manual field fix and documentation. User notified.', 'Chief Warden')}
                                    className="flex-1 py-5 bg-emerald-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-emerald-500 shadow-2xl shadow-emerald-900/40 transition-all flex items-center justify-center gap-3"
                                  >Verify Proof & Close Incident</button>
                                  <button 
                                    onClick={() => handleUpdateStatus(r.id, 'assigned', 'Documentation rejected. Proof of work insufficient.', 'Chief Warden')}
                                    className="px-10 py-5 bg-red-500/10 text-red-400 rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-red-500/20 transition-all border border-red-500/20"
                                  >Reject Proof</button>
                               </div>
                             </div>
                           )}
                        </div>
                      )}

                      {/* AGENCY PROTOCOL: Manual Field Fix + Completion Photo */}
                      {user?.role === 'authority' && (
                        <div className="bg-amber-500/5 p-10 rounded-[3rem] border border-amber-500/10 space-y-8">
                           {r.status === 'assigned' && (
                             <div className="space-y-8">
                               <div className="flex items-center justify-between">
                                  <p className="text-[10px] font-black text-amber-400 uppercase tracking-widest">Operational Task: Manual Field Intervention</p>
                                  <span className="text-[10px] font-black text-slate-600">MANDATORY DOCUMENTATION</span>
                               </div>

                               <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                                  <div className="space-y-4">
                                     <p className="text-xs font-bold text-slate-400 pl-2">1. Resolution Summary</p>
                                     <textarea 
                                        value={agencyActionText}
                                        onChange={(e) => setAgencyActionText(e.target.value)}
                                        placeholder="Manually detail the specific field work performed (e.g., 'Cleared blockage in Sector 4 drainage, replaced rusted grate')..."
                                        className="w-full bg-white/5 border border-white/10 rounded-3xl p-6 font-bold text-white focus:ring-4 focus:ring-amber-500/10 outline-none transition-all min-h-[160px]"
                                     />
                                  </div>
                                  <div className="space-y-4">
                                     <p className="text-xs font-bold text-slate-400 pl-2">2. Completion Photo (After)</p>
                                     <div 
                                        onClick={() => proofInputRef.current?.click()}
                                        className="w-full aspect-video bg-white/5 border-2 border-dashed border-white/10 rounded-3xl flex flex-col items-center justify-center cursor-pointer hover:bg-white/10 transition-all overflow-hidden relative group"
                                     >
                                        {agencyProofImage ? (
                                          <>
                                            <img src={agencyProofImage} className="w-full h-full object-cover" />
                                            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                                               <span className="text-[10px] font-black text-white uppercase tracking-widest">Change Proof Photo</span>
                                            </div>
                                          </>
                                        ) : (
                                          <div className="text-center">
                                             <svg className="w-12 h-12 text-slate-700 mx-auto mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2"/></svg>
                                             <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Upload Documentation</p>
                                          </div>
                                        )}
                                        <input type="file" hidden ref={proofInputRef} onChange={handleProofUpload} accept="image/*" />
                                     </div>
                                  </div>
                               </div>

                               <button 
                                  disabled={!agencyActionText.trim() || !agencyProofImage}
                                  onClick={() => handleUpdateStatus(r.id, 'solved_by_authority', `Field Work Complete: ${agencyActionText}`, user.organization || 'Agency', { resolutionDetails: agencyActionText, resolvedImageUrl: agencyProofImage, resolvedTimestamp: new Date() })}
                                  className="w-full py-6 bg-amber-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] hover:bg-amber-500 disabled:opacity-30 transition-all shadow-2xl shadow-amber-900/60 active:scale-95"
                                >Intimate Field Resolution to Command</button>
                             </div>
                           )}
                        </div>
                      )}

                      {/* USER FEEDBACK */}
                      {user?.role === 'user' && (
                        <div className="bg-emerald-500/5 p-12 rounded-[4rem] border border-emerald-500/10">
                           <div className="flex flex-col md:flex-row items-center gap-12">
                              <div className={`w-32 h-32 rounded-[2.5rem] flex items-center justify-center text-white shadow-3xl transition-all duration-1000 ${
                                r.status === 'resolved' ? 'bg-emerald-500 scale-110' : 'bg-slate-700'
                              }`}>
                                 {r.status === 'resolved' ? <svg className="w-16 h-16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="4"/></svg> : <svg className="w-16 h-16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="4"/></svg>}
                              </div>
                              <div className="flex-1 text-center md:text-left">
                                 <h4 className="text-4xl font-black text-white tracking-tighter mb-4">
                                   {r.status === 'pending' && "Evidence Received."}
                                   {r.status === 'assigned' && "Agency Dispatched."}
                                   {r.status === 'solved_by_authority' && "Field Work Done."}
                                   {r.status === 'resolved' && "Incident Restored."}
                                 </h4>
                                 <p className="text-xl text-slate-400 font-bold leading-relaxed mb-6">
                                   {r.status === 'pending' && "Sentinel AI has verified the coordinates. Command is triaging for unit dispatch."}
                                   {r.status === 'assigned' && `The ${r.assignedAuthorityId} unit is physically at the site for restoration.`}
                                   {r.status === 'solved_by_authority' && "Documentation of the fix is being reviewed by Command for final approval."}
                                   {r.status === 'resolved' && "Restoration complete. Check the resolution proof above. Impact Points Awarded!"}
                                 </p>
                                 <div className="inline-flex items-center gap-3 px-6 py-2 bg-white/5 border border-white/5 rounded-2xl text-[10px] font-black text-slate-500 uppercase tracking-widest">Grid Operational Update: {new Date().toLocaleTimeString()}</div>
                              </div>
                           </div>
                        </div>
                      )}
                   </div>

                   {/* Timeline Footer */}
                   <div className="bg-black/20 p-12 border-t border-white/5">
                      <div className="flex items-center gap-10">
                        <div className="flex-1 space-y-6 relative pl-10">
                           <div className="absolute left-[5px] top-2 bottom-2 w-0.5 bg-white/5" />
                           {r.timeline.map((evt, idx) => (
                             <div key={idx} className="relative">
                                <div className={`absolute -left-[40px] top-1.5 w-4 h-4 rounded-full border-4 border-[#0f172a] shadow-sm ${
                                  idx === r.timeline.length-1 ? (evt.status === 'resolved' ? 'bg-emerald-500' : 'bg-indigo-500') : 'bg-slate-700'
                                }`} />
                                <div className="flex justify-between items-center">
                                   <div>
                                      <p className="text-sm font-black text-white tracking-tight leading-none">{evt.message}</p>
                                      <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mt-1">Personnel: <span className="text-slate-300">{evt.actor}</span></p>
                                   </div>
                                   <span className="text-[10px] font-bold text-slate-600 bg-white/5 px-2 py-1 rounded-lg">{new Date(evt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                </div>
                             </div>
                           ))}
                        </div>
                      </div>
                   </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { analyzeEnvironmentalImage } from '../services/geminiService.ts';
import { AIAnalysisResult, IncidentType, Severity, Report } from '../types.ts';

interface ReportWizardProps {
  onComplete: (report: Partial<Report>) => void;
}

const ReportWizard: React.FC<ReportWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AIAnalysisResult | null>(null);
  const [description, setDescription] = useState('');
  const [manualAddress, setManualAddress] = useState('');
  const [location, setLocation] = useState<{lat: number, lng: number, address: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const initialAddr = "Fetching address from coordinates...";
        setLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          address: initialAddr
        });
        setManualAddress(initialAddr);

        // Simulated reverse geocoding
        setTimeout(() => {
          const detected = `Sector ${Math.floor(Math.random()*100)}, Green Zone Highway`;
          setLocation(prev => prev ? ({...prev, address: detected}) : null);
          setManualAddress(detected);
        }, 1500);
      }, (err) => {
        setManualAddress("Manual input required - GPS unavailable");
      });
    }
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setStep(2);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartAnalysis = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeEnvironmentalImage(base64Data);
      setAnalysis(result);
      setStep(3);
    } catch (err) {
      alert("AI analysis failed. Please enter details manually.");
      setStep(3);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSubmit = () => {
    onComplete({
      type: analysis?.detectedType || IncidentType.OTHER,
      severity: analysis?.severity || Severity.MEDIUM,
      description: description || analysis?.explanation || '',
      imageUrl: image || undefined,
      aiInsights: analysis?.explanation,
      location: { 
        lat: location?.lat || 0, 
        lng: location?.lng || 0, 
        address: manualAddress || location?.address || "Manual Input Location" 
      },
      timestamp: new Date(),
    });
  };

  return (
    <div className="bg-white rounded-[4rem] p-12 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.1)] max-w-xl mx-auto border border-slate-100 animate-slide-up">
      <div className="flex items-center gap-4 mb-12">
        {[1, 2, 3].map((s) => (
          <div key={s} className="flex-1 h-1.5 rounded-full bg-slate-100 overflow-hidden">
            <div className={`h-full transition-all duration-700 ${step >= s ? 'bg-emerald-500' : 'bg-transparent'}`} />
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="text-center py-10">
          <div className="w-24 h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 text-emerald-600 shadow-inner">
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
          </div>
          <h2 className="text-4xl font-black mb-4 tracking-tighter">Visual Evidence</h2>
          <p className="text-slate-500 mb-12 font-medium">Capture or upload high-resolution media to initialize the environmental grid report.</p>
          <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
          <button onClick={() => fileInputRef.current?.click()} className="w-full bg-slate-900 text-white font-black py-6 rounded-3xl shadow-2xl hover:bg-black transition-all active:scale-[0.98]">Select Media Artifact</button>
        </div>
      )}

      {step === 2 && image && (
        <div className="text-center">
          <div className="relative group mb-10">
            <img src={image} className="w-full aspect-square object-cover rounded-[3rem] shadow-2xl" alt="Evidence" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity rounded-[3rem] flex items-center justify-center">
              <button onClick={() => setImage(null)} className="p-5 bg-white/20 backdrop-blur-md rounded-full text-white">
                <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2.5"/></svg>
              </button>
            </div>
          </div>
          <h2 className="text-3xl font-black mb-3 tracking-tighter text-slate-900">Sentinel Intelligence</h2>
          <p className="text-slate-500 mb-10 font-medium">Process the media through our environmental computer vision for rapid triage.</p>
          <div className="flex gap-4">
            <button disabled={analyzing} onClick={handleStartAnalysis} className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-3xl shadow-xl hover:bg-indigo-700 disabled:opacity-50 transition-all flex items-center justify-center gap-4 active:scale-[0.98]">
              {analyzing ? (
                <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2.5"/></svg>
              )}
              {analyzing ? "Analyzing Feed..." : "Initialize Deep Scan"}
            </button>
            <button disabled={analyzing} onClick={() => setStep(3)} className="px-10 border border-slate-200 font-black py-5 rounded-3xl text-slate-400 hover:bg-slate-50 transition-all">Skip AI</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">

          {/* Manual Address Input Section */}
          <div className="space-y-4">
            <div className="flex items-center justify-between pl-2">
               <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                  <svg className="w-4 h-4 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" strokeWidth="2.5"/></svg>
                  Physical Location
               </h4>
               <span className="text-[9px] font-black text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-lg border border-emerald-100 uppercase tracking-widest">Manual Correction Enabled</span>
            </div>
            <div className="relative group">
              <input 
                type="text" 
                value={manualAddress} 
                onChange={(e) => setManualAddress(e.target.value)}
                placeholder="Enter specific landmark or site address..."
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl px-8 py-5 font-bold text-slate-900 focus:ring-4 focus:ring-emerald-500/5 focus:border-emerald-500/40 outline-none transition-all group-hover:border-slate-200"
              />
              <div className="absolute right-6 top-1/2 -translate-y-1/2 w-8 h-8 bg-white rounded-xl shadow-sm flex items-center justify-center">
                 <svg className="w-4 h-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" strokeWidth="2.5"/></svg>
              </div>
            </div>
          </div>

          {/* AI Synthesis Summary */}
          <div className="grid grid-cols-2 gap-4">
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100 flex flex-col justify-center">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Categorization</p>
                <p className="text-sm font-black text-slate-900">{analysis?.detectedType || 'Pending Verification'}</p>
             </div>
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100 flex flex-col justify-center">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Severity Vector</p>
                <p className={`text-sm font-black ${analysis?.severity === Severity.CRITICAL ? 'text-red-600' : 'text-orange-500'}`}>{analysis?.severity || 'Medium'}</p>
             </div>
          </div>

          {/* Observations / Description */}
          <div className="space-y-4">
            <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] pl-2">Field Observations</h4>
            <div className="bg-white border-2 border-slate-900 rounded-[2.5rem] p-1 shadow-[4px_4px_0px_#0f172a] focus-within:shadow-[6px_6px_0px_#10b981] transition-all">
               <textarea 
                  value={description} 
                  onChange={(e) => setDescription(e.target.value)} 
                  placeholder="Describe colors, odors, sounds, or physical damage observed..." 
                  className="w-full bg-transparent p-6 font-bold text-slate-900 placeholder:text-slate-300 outline-none min-h-[160px] resize-none" 
               />
            </div>
          </div>

          {/* Final Submission Button */}
          <button 
            onClick={handleSubmit} 
            className="w-full bg-[#059669] text-white font-black py-6 rounded-full shadow-[0_20px_40px_-12px_rgba(5,150,105,0.4)] hover:bg-[#047857] hover:translate-y-[-2px] active:scale-[0.97] transition-all text-lg tracking-tight"
          >
            Submit Secure Report
          </button>
        </div>
      )}
    </div>
  );
};

