  const [bookmarkedIds, setBookmarkedIds] = useState<string[]>([]);

  // Load bookmarks from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('terrasentinel_bookmarks');
    if (saved) {
      try {
        setBookmarkedIds(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load bookmarks");
      }
    }
  }, []);

  // Save bookmarks to local storage whenever they change
  const toggleBookmark = (id: string) => {
    const newBookmarks = bookmarkedIds.includes(id)
      ? bookmarkedIds.filter(bid => bid !== id)
      : [...bookmarkedIds, id];

    setBookmarkedIds(newBookmarks);
    localStorage.setItem('terrasentinel_bookmarks', JSON.stringify(newBookmarks));
  };

  const filteredResources = filter === 'all' 
    ? RESOURCES 
    : RESOURCES.filter(r => r.category === filter);

  const categories = [
