import React, { useState, useEffect } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { generateCommunityUpdate } from '../services/geminiService.js';

const data = [
  { name: 'Mon', incidents: 12 },
  { name: 'Tue', incidents: 19 },
  { name: 'Wed', incidents: 14 },
  { name: 'Thu', incidents: 32 },
  { name: 'Fri', incidents: 22 },
  { name: 'Sat', incidents: 45 },
  { name: 'Sun', incidents: 28 },
];

const LIVE_FEEDS = [
  "New land damage reported in Sector 82...",
  "Forestry Commission deployed to Northern Ridge...",
  "Wildlife Rescue Unit cleared Case R-902.",
  "Atmospheric sensors detect rise in smog at Urban Edge.",
  "Community member John Sentinel earned 50 credits.",
  "Ocean SOS node activated near Coastal Zone B."
];

const Dashboard = ({ reports, user, onNewReport, onNavigate }) => {
  const [aiSummary, setAiSummary] = useState("EcoGuard is cross-referencing recent environmental data streams...");
  const [currentFeedIdx, setCurrentFeedIdx] = useState(0);

  useEffect(() => {
    const fetchSummary = async () => {
      if (reports.length > 0) {
        try {
          const summary = await generateCommunityUpdate(reports.slice(0, 5));
          setAiSummary(summary);
        } catch (e) {
          setAiSummary("The EcoGuard network remains fully operational.");
        }
      }
    };
    fetchSummary();

    const interval = setInterval(() => {
      setCurrentFeedIdx(prev => (prev + 1) % LIVE_FEEDS.length);
    }, 4000);
    return () => clearInterval(interval);
  }, [reports]);

  const isAdmin = user.role === 'admin';
  const isAuth = user.role === 'authority';

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className={`relative overflow-hidden rounded-[4rem] p-12 md:p-20 text-white shadow-3xl ${
        isAdmin ? 'bg-gradient-to-br from-indigo-950 to-slate-900' :
        isAuth ? 'bg-gradient-to-br from-amber-950 to-slate-900' :
