import React, { useState, useRef, useEffect } from 'react';
import { analyzeEnvironmentalImage } from '../services/geminiService.js';
import { IncidentType, Severity } from '../types.js';

const ReportWizard = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState(null);
  const [description, setDescription] = useState('');
  const [manualAddress, setManualAddress] = useState('');
  const [location, setLocation] = useState(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const initialAddr = "Locking GPS coordinates...";
        setLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          address: initialAddr
        });
        setManualAddress(initialAddr);
        setTimeout(() => {
          const detected = `District ${Math.floor(Math.random()*100)}, Nature Corridor B`;
          setLocation(prev => prev ? ({...prev, address: detected}) : null);
          setManualAddress(detected);
        }, 1500);
      }, () => {
        setManualAddress("Manual input required - GPS unavailable");
      });
    }
  }, []);

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result);
        setStep(2);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartAnalysis = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeEnvironmentalImage(base64Data);
      setAnalysis(result);
      setStep(3);
    } catch (err) {
      alert("AI analysis failed. Please enter details manually.");
      setStep(3);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSubmit = () => {
    onComplete({
      type: analysis?.detectedType || IncidentType.OTHER,
      severity: analysis?.severity || Severity.MEDIUM,
      description: description || analysis?.explanation || '',
      imageUrl: image || undefined,
      aiInsights: analysis?.explanation,
      location: { 
        lat: location?.lat || 0, 
        lng: location?.lng || 0, 
        address: manualAddress || location?.address || "Manual Site Input" 
      },
      timestamp: new Date(),
    });
  };

  return (
    <div className="bg-white rounded-[4rem] p-12 shadow-2xl max-w-xl mx-auto border border-slate-100 animate-slide-up">
      <div className="flex items-center gap-4 mb-12">
        {[1, 2, 3].map((s) => (
          <div key={s} className="flex-1 h-1.5 rounded-full bg-slate-100 overflow-hidden">
            <div className={`h-full transition-all duration-700 ${step >= s ? 'bg-emerald-500' : 'bg-transparent'}`} />
          </div>
        ))}
      </div>
      {step === 1 && (
        <div className="text-center py-10">
          <div className="w-24 h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 text-emerald-600 shadow-inner">
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
          </div>
          <h2 className="text-4xl font-black mb-4 tracking-tighter">Site Evidence</h2>
          <p className="text-slate-500 mb-12 font-medium">Capture or upload media to initialize the audit.</p>
          <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
          <button onClick={() => fileInputRef.current?.click()} className="w-full bg-slate-900 text-white font-black py-6 rounded-3xl shadow-2xl active:scale-[0.98]">Select Evidence Artifact</button>
        </div>
      )}
      {step === 2 && image && (
        <div className="text-center">
          <div className="relative group mb-10">
            <img src={image} className="w-full aspect-square object-cover rounded-[3rem] shadow-2xl" alt="Evidence" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity rounded-[3rem] flex items-center justify-center">
              <button onClick={() => setImage(null)} className="p-5 bg-white/20 backdrop-blur-md rounded-full text-white">
                <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2.5"/></svg>
              </button>
            </div>
          </div>
          <h2 className="text-3xl font-black mb-3 tracking-tighter text-slate-900">EcoGuard Vision</h2>
          <div className="flex gap-4">
            <button disabled={analyzing} onClick={handleStartAnalysis} className="flex-1 bg-indigo-600 text-white font-black py-5 rounded-3xl shadow-xl hover:bg-indigo-700 disabled:opacity-50 transition-all flex items-center justify-center gap-4 active:scale-[0.98]">
              {analyzing ? (
                <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeWidth="2.5"/></svg>
              )}
              {analyzing ? "Synthesizing Data..." : "Run Neural Audit"}
            </button>
            <button disabled={analyzing} onClick={() => setStep(3)} className="px-10 border border-slate-200 font-black py-5 rounded-3xl text-slate-400 hover:bg-slate-50 transition-all">Manual Entry</button>
          </div>
        </div>
      )}
      {step === 3 && (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="space-y-4">
            <div className="flex items-center justify-between pl-2">
               <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                  <svg className="w-4 h-4 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" strokeWidth="2.5"/></svg>
                  Physical Coordinates
               </h4>
            </div>
            <input 
              type="text" 
              value={manualAddress} 
              onChange={(e) => setManualAddress(e.target.value)}
              placeholder="Address..."
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl px-8 py-5 font-bold text-slate-900 focus:ring-4 outline-none transition-all"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Anomaly Class</p>
                <p className="text-sm font-black text-slate-900">{analysis?.detectedType || 'Pending'}</p>
             </div>
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Severity Vector</p>
                <p className="text-sm font-black text-orange-500">{analysis?.severity || 'Standard'}</p>
             </div>
          </div>
          <textarea 
             value={description} 
             onChange={(e) => setDescription(e.target.value)} 
             placeholder="Audit details..." 
             className="w-full border-2 border-slate-900 rounded-[2.5rem] p-6 font-bold text-slate-900 outline-none min-h-[160px] resize-none" 
          />
          <button onClick={handleSubmit} className="w-full bg-[#059669] text-white font-black py-6 rounded-full shadow-2xl active:scale-[0.97] transition-all text-lg">
            Authorize Secure Dispatch
          </button>
        </div>
      )}
    </div>
  );
};

export default ReportWizard;

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService.js';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

const Login = ({ onLoginSuccess }) => {
  const [view, setView] = useState('selector');
  const [role, setRole] = useState('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [org, setOrg] = useState(AUTHORITIES[0]);

  const selectPortal = (selectedRole) => {
    setRole(selectedRole);
    setView('login');
    setEmail('');
    setPassword('');
    setName('');
    setError('');
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      if (view === 'register') {
        const newUser = await registerUser(name, email, role, role === 'authority' ? org : undefined);
        onLoginSuccess(newUser);
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err) {
      setError(err.message || "Authentication failed.");
      setLoading(false);
    }
  };

  const handleGoogleLogin = () => {
    setLoading(true);
    setTimeout(() => {
      onLoginSuccess({
        id: 'google-user-123',
        name: 'John Sentinel',
        email: 'john@gmail.com',
        role: role,
        points: 150,
        reportsCount: 2,
        avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=John',
        organization: role === 'authority' ? org : undefined
      });
    }, 1500);
  };

  const themeMap = {
    admin: { bg: 'bg-[#0f172a]', text: 'text-indigo-400', btn: 'bg-indigo-600 hover:bg-indigo-500', label: 'Admin' },
    authority: { bg: 'bg-[#1a1408]', text: 'text-amber-400', btn: 'bg-amber-600 hover:bg-amber-500', label: 'Authority' },
    user: { bg: 'bg-[#061e1a]', text: 'text-emerald-400', btn: 'bg-emerald-600 hover:bg-emerald-500', label: 'User' }
  };
  const theme = themeMap[role];

  if (view === 'selector') {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 relative overflow-hidden">
        <div className="relative z-10 w-full max-w-7xl text-center space-y-16">
          <h1 className="text-6xl md:text-9xl font-black text-white tracking-tighter">EcoGuard</h1>
          <div className="grid md:grid-cols-3 gap-10 px-4">
            {['user', 'authority', 'admin'].map(r => (
              <button key={r} onClick={() => selectPortal(r)} className="group bg-[#0f172a] border border-white/5 p-12 rounded-[4rem] text-left hover:border-emerald-500/30 transition-all duration-500 hover:-translate-y-4">
                <h3 className="text-4xl font-black text-white mb-4 tracking-tight capitalize">{r}</h3>
                <p className="text-slate-400 text-lg opacity-60">Establish node authorization.</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen transition-all duration-1000 ${theme.bg} flex flex-col items-center justify-center p-6 relative overflow-hidden`}>
      <div className="relative z-10 w-full max-w-xl bg-white rounded-[4rem] p-16 shadow-2xl animate-slide-up">
        <button onClick={() => setView('selector')} className="text-slate-400 hover:text-slate-900 transition-colors text-[10px] font-black uppercase tracking-widest mb-10">
          Return to Selection
        </button>
        <div className="text-center mb-10">
          <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${theme.text} mb-4`}>{theme.label} Node</p>
          <h2 className="text-5xl font-black text-slate-900">{view === 'login' ? 'Access Key' : 'Join Network'}</h2>
        </div>
        <div className="space-y-6">
          <button type="button" onClick={handleGoogleLogin} disabled={loading} className="w-full flex items-center justify-center gap-4 py-5 bg-white border-2 border-slate-100 rounded-[2rem] font-bold text-slate-700 hover:bg-slate-50 transition-all active:scale-95 disabled:opacity-50">
            Sign in with Google
          </button>
          <form onSubmit={handleAuth} className="space-y-6">
            {view === 'register' && (
              <input type="text" required value={name} onChange={(e) => setName(e.target.value)} placeholder="Full Name" className="w-full px-8 py-5 bg-slate-50 border rounded-3xl font-bold" />
            )}
            <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" className="w-full px-8 py-5 bg-slate-50 border rounded-3xl font-bold" />
            <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" className="w-full px-8 py-5 bg-slate-50 border rounded-3xl font-bold" />
            {error && <div className="text-red-600 text-[10px] font-black p-4">{error}</div>}
            <button disabled={loading} type="submit" className={`w-full py-6 rounded-[2rem] font-black text-white shadow-2xl transition-all ${theme.btn}`}>
              {loading ? 'Initializing...' : view === 'login' ? 'Link Node' : 'Register Node'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

