import React, { useState, useEffect } from 'react';

const RESOURCES = [
  { id: 'e1', title: 'Forest Fire Hotline', content: 'Urgent reports.', category: 'emergency', icon: '🔥', phone: '1-800-FIRE-ECO' },
  { id: 'n1', title: 'Elephant corridor', content: 'Safety notes.', category: 'note', icon: '🐘' },
  { id: 'w1', title: 'Bengal Tiger', content: 'Endangered.', category: 'wildlife', icon: '🐅' },
  { id: 'l1', title: 'Global Wildlife Fund', content: 'WWF.', category: 'link', url: 'https://www.worldwildlife.org' },
];

const Resources = () => {
  const [filter, setFilter] = useState('all');
  const [bookmarkedIds, setBookmarkedIds] = useState([]);

  useEffect(() => {
    const saved = localStorage.getItem('ecoguard_bookmarks');
    if (saved) setBookmarkedIds(JSON.parse(saved));
  }, []);

  const toggleBookmark = (id) => {
    const newBookmarks = bookmarkedIds.includes(id) ? bookmarkedIds.filter(bid => bid !== id) : [...bookmarkedIds, id];
    setBookmarkedIds(newBookmarks);
    localStorage.setItem('ecoguard_bookmarks', JSON.stringify(newBookmarks));
  };

  const filteredResources = filter === 'all' ? RESOURCES : RESOURCES.filter(r => r.category === filter);

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-8">
        <h2 className="text-4xl font-black text-slate-900">Guardian Library</h2>
        <div className="flex bg-slate-50 p-2 rounded-2xl gap-1 overflow-x-auto">
          {['all', 'emergency', 'note', 'wildlife', 'link'].map(cat => (
            <button key={cat} onClick={() => setFilter(cat)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === cat ? 'bg-slate-900 text-white' : 'text-slate-400'}`}>
              {cat}
            </button>
          ))}
        </div>
      </div>
      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredResources.map((r) => (
