import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

const ChatSentinel = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { role: 'model', text: `Greetings, ${user.name}. How can I assist?`, timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    const userMessage = { role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, userMessage].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: "You are the EcoGuard Sentinel AI." }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "...", timestamp: new Date() }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Connection error.", timestamp: new Date() }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-32 right-8 lg:bottom-12 lg:right-12 z-[100]">
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[380px] h-[550px] bg-[#020617] rounded-[3rem] border border-white/10 flex flex-col overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10 fade-in duration-500">
          <div className="p-8 bg-gradient-to-r from-[#0f172a] to-[#061e1a] border-b border-white/5 flex items-center justify-between text-white">
            <h3 className="font-black">Sentinel AI</h3>
            <button onClick={() => setIsOpen(false)}>Close</button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm ${m.role === 'user' ? 'bg-emerald-600 text-white' : 'bg-white/5 text-slate-300'}`}>
                  {m.text}
                </div>
              </div>
            ))}
          </div>
          <form onSubmit={handleSendMessage} className="p-6 border-t border-white/5">
            <input type="text" value={input} onChange={(e) => setInput(e.target.value)} placeholder="Query grid..." className="w-full bg-[#0f172a] border border-white/10 rounded-2xl px-6 py-4 text-white outline-none" />
          </form>
        </div>
      )}
      <button onClick={() => setIsOpen(!isOpen)} className="w-16 h-16 rounded-full bg-emerald-600 flex items-center justify-center text-white shadow-xl transition-all hover:scale-110">
        AI
      </button>
    </div>
  );
};

export default ChatSentinel;

