import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/authService';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

const Login = ({ onLoginSuccess }) => {
  const [view, setView] = useState('selector');
  const [role, setRole] = useState('user');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [org, setOrg] = useState(AUTHORITIES[0]);

  const selectPortal = (selectedRole) => {
    setRole(selectedRole);
    setView('login');
    resetForms();
  };

  const resetForms = () => {
    setEmail('');
    setPassword('');
    setName('');
    setError('');
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      if (view === 'register') {
        const newUser = await registerUser(name, email, role, role === 'authority' ? org : undefined);
        onLoginSuccess(newUser);
      } else {
        const user = await loginUser(email, password, role);
        onLoginSuccess(user);
      }
    } catch (err) {
      setError(err.message || "Authentication failed.");
      setLoading(false);
    }
  };

  const handleGoogleLogin = () => {
    setLoading(true);
    setTimeout(() => {
      onLoginSuccess({
        id: 'google-user-123',
        name: 'John Sentinel',
        email: 'john@gmail.com',
        role: role,
        points: 150,
        reportsCount: 2,
        avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=John',
        organization: role === 'authority' ? AUTHORITIES[0] : undefined
      });
    }, 1500);
  };

  const themeMap = {
    admin: { bg: 'bg-[#0f172a]', text: 'text-indigo-400', btn: 'bg-indigo-600 hover:bg-indigo-500', label: 'Admin' },
    authority: { bg: 'bg-[#1a1408]', text: 'text-amber-400', btn: 'bg-amber-600 hover:bg-amber-500', label: 'Authority' },
    user: { bg: 'bg-[#061e1a]', text: 'text-emerald-400', btn: 'bg-emerald-600 hover:bg-emerald-500', label: 'User' }
  };
  const theme = themeMap[role];

  if (view === 'selector') {
    return (
      <div className="min-h-screen bg-[#020617] flex flex-col items-center justify-center p-6 relative overflow-hidden">
        <div className="relative z-10 w-full max-w-7xl text-center space-y-16">
          <h1 className="text-6xl md:text-9xl font-black text-white tracking-tighter">EcoGuard</h1>
          <div className="grid md:grid-cols-3 gap-10 px-4">
            {['user', 'authority', 'admin'].map(r => (
              <button key={r} onClick={() => selectPortal(r)} className="group bg-[#0f172a] border border-white/5 p-12 rounded-[4rem] text-left hover:border-emerald-500/30 transition-all duration-500 hover:-translate-y-4">
                <h3 className="text-4xl font-black text-white mb-4 tracking-tight capitalize">{r}</h3>
                <p className="text-slate-400 text-lg opacity-60">Establish node authorization.</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen transition-all duration-1000 ${theme.bg} flex flex-col items-center justify-center p-6 relative overflow-hidden`}>
