          <div className="space-y-4">
            <div className="flex items-center justify-between pl-2">
               <h4 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] flex items-center gap-2">
                  <svg className="w-4 h-4 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" strokeWidth="2.5"/></svg>
                  Physical Coordinates
               </h4>
            </div>
            <input 
              type="text" 
              value={manualAddress} 
              onChange={(e) => setManualAddress(e.target.value)}
              placeholder="Address..."
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl px-8 py-5 font-bold text-slate-900 focus:ring-4 outline-none transition-all"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Anomaly Class</p>
                <p className="text-sm font-black text-slate-900">{analysis?.detectedType || 'Pending'}</p>
             </div>
             <div className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Severity Vector</p>
                <p className="text-sm font-black text-orange-500">{analysis?.severity || 'Standard'}</p>
             </div>
          </div>
          <textarea 
             value={description} 
             onChange={(e) => setDescription(e.target.value)} 
             placeholder="Audit details..." 
             className="w-full border-2 border-slate-900 rounded-[2.5rem] p-6 font-bold text-slate-900 outline-none min-h-[160px] resize-none" 
          />
          <button onClick={handleSubmit} className="w-full bg-[#059669] text-white font-black py-6 rounded-full shadow-2xl active:scale-[0.97] transition-all text-lg">
            Authorize Secure Dispatch
          </button>
        </div>
      )}
    </div>
  );
};

export default ReportWizard;

import { GoogleGenAI, Type } from "@google/genai";
import { IncidentType, Severity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeEnvironmentalImage = async (base64Image) => {
  const model = 'gemini-3-flash-preview';

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Analyze this image for environmental or wildlife concerns. 
          Identify if it shows land damage, illegal tree cutting, injured animals, or road accidents. 
          Assess the severity and provide a short explanation and recommended immediate action.`,
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedType: {
            type: Type.STRING,
            description: "Category of the incident",
          },
          severity: {
            type: Type.STRING,
            description: "Severity level",
          },
          explanation: {
            type: Type.STRING,
            description: "Concise description",
          },
          recommendedAction: {
            type: Type.STRING,
            description: "Recommendation",
          },
        },
        required: ["detectedType", "severity", "explanation", "recommendedAction"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Could not interpret AI analysis.");
  return JSON.parse(text);
};

export const generateCommunityUpdate = async (recentReports) => {
  const model = 'gemini-3-flash-preview';
  const response = await ai.models.generateContent({
    model,
    contents: `Write a short, inspiring 2-sentence summary for a community dashboard based on these reports: ${JSON.stringify(recentReports)}`
  });
  return response.text || "Every report helps us protect our shared natural environment.";
};

