        setTimeout(() => {
          const detected = `District ${Math.floor(Math.random()*100)}, Nature Corridor B`;
          setLocation(prev => prev ? ({...prev, address: detected}) : null);
          setManualAddress(detected);
        }, 1500);
      }, () => {
