  };

  const handleNewReport = (reportData: any) => {
    const newReport = {
      ...reportData,
      id: `R-${Math.floor(Math.random() * 900) + 100}`,
      status: 'pending',
      reporterId: user?.id || 'anonymous',
      timeline: [{
        status: 'pending',
        timestamp: new Date(),
        message: 'Incident reported. Dispatched to Global Command for triage.',
        actor: user?.name || 'Anonymous'
      }]
    };
    setReports([newReport, ...reports]);
    setActiveTab('reports');
  };

  const handleUpdateStatus = (id: string, newStatus: string, message: string, actor: string) => {
    setReports(prev => prev.map(r => {
      if (r.id === id) {
        return {
          ...r,
          status: newStatus,
          timeline: [...r.timeline, { status: newStatus, timestamp: new Date(), message, actor }]
        };
      }
      return r;
    }));
  };

  if (!isAuthenticated) return <Login onLoginSuccess={handleAuthSuccess} />;

  return (
    <Layout user={user} onLogout={() => setIsAuthenticated(false)} activeTab={activeTab} setActiveTab={setActiveTab}>
