              Active Monitoring: {reports.length} Nodes
            </div>
          </div>

          <div className="grid gap-6">
            {reports.map(r => (
              <div key={r.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-xl overflow-hidden flex flex-col md:flex-row group transition-all hover:shadow-2xl hover:border-emerald-200">
                <div className="md:w-1/3 h-64 md:h-auto relative">
                  <img src={r.imageUrl} className="w-full h-full object-cover" alt="Incident" />
