                  <div>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center gap-3">
                        <div className={`w-3 h-3 rounded-full animate-pulse ${
                          r.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500'
                        }`} />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status: {r.status}</span>
