import React, { useState, useRef } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { IncidentType, Severity } from '../types.ts';

const ReportWizard: React.FC<{ onComplete: (d: any) => void }> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);
  const [desc, setDesc] = useState('');
  const fileRef = useRef<HTMLInputElement>(null);

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const runVisionAudit = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          { inlineData: { mimeType: 'image/jpeg', data: image.split(',')[1] } },
          { text: "Analyze this environmental concern. Return JSON with 'type' (Land Damage, Illegal Logging, Injured Wildlife, Animal Road Accident, Pollution, Other), 'severity' (Low, Medium, High, Critical), and 'explanation'." }
        ],
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              severity: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ['type', 'severity', 'explanation']
          }
        }
      });
      setAnalysis(JSON.parse(response.text || '{}'));
      setStep(2);
    } catch (e) {
      alert("AI analysis failed. Please fill details manually.");
      setStep(2);
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto bg-white rounded-[3rem] p-12 shadow-2xl border border-slate-100 animate-slide-up">
      {step === 1 && (
        <div className="text-center">
          <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-8 text-emerald-600">
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
          </div>
          <h2 className="text-3xl font-black mb-4">Capture Evidence</h2>
