import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

const ChatSentinel: React.FC<{ user: any }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<any[]>([
    { role: 'model', text: `Greetings ${user.name}. I am the Sentinel. How can I assist your mission today?` }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, loading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, userMsg].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: "You are the EcoGuard Sentinel. Provide concise, professional, and action-oriented environmental advice." }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "..." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Signal lost. Attempting reconnection..." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-12 right-12 z-[200]">
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[400px] h-[600px] bg-white rounded-[3rem] shadow-[0_50px_100px_rgba(0,0,0,0.2)] border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 duration-500">
          <div className="p-8 bg-slate-900 text-white flex items-center justify-between">
            <h3 className="font-black tracking-tight">Sentinel Assistant</h3>
            <button onClick={() => setIsOpen(false)} className="opacity-60 hover:opacity-100">Close</button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm font-medium leading-relaxed ${m.role === 'user' ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-800'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && <div className="text-xs font-black text-slate-400 uppercase tracking-widest animate-pulse">Sentinel is thinking...</div>}
          </div>
          <form onSubmit={handleSend} className="p-6 border-t border-slate-100">
            <input 
              value={input} 
              onChange={e => setInput(e.target.value)}
              placeholder="Query the grid..." 
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 outline-none focus:ring-4 focus:ring-emerald-500/10 transition-all font-bold text-slate-900" 
            />
          </form>
        </div>
      )}
      <button onClick={() => setIsOpen(!isOpen)} className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center text-white shadow-2xl hover:scale-110 active:scale-95 transition-all border-4 border-white">
        <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2.5"/></svg>
      </button>
    </div>
  );
};

