import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysisResult, IncidentType, Severity } from "../types";

export const analyzeEnvironmentalImage = async (base64Image: string): Promise<AIAnalysisResult> => {
  // Initializing inside the function to follow guidelines for up-to-date API keys
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Analyze this image for environmental or wildlife concerns. 
          Identify if it shows land damage, illegal tree cutting, injured animals, or road accidents. 
          Assess the severity and provide a short explanation and recommended immediate action.`,
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedType: {
            type: Type.STRING,
            description: "Category of the incident",
          },
          severity: {
            type: Type.STRING,
            description: "Severity level",
          },
          explanation: {
            type: Type.STRING,
            description: "Concise description",
          },
          recommendedAction: {
            type: Type.STRING,
            description: "Recommendation",
          },
        },
        required: ["detectedType", "severity", "explanation", "recommendedAction"],
      },
    },
  });

  // response.text is a property
  const text = response.text;
  if (!text) throw new Error("Could not interpret AI analysis.");
  return JSON.parse(text) as AIAnalysisResult;
};

export const generateCommunityUpdate = async (recentReports: any[]) => {
  // Initializing inside the function to follow guidelines for up-to-date API keys
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';
  const response = await ai.models.generateContent({
    model,
    contents: `Write a short, inspiring 2-sentence summary for a community dashboard: ${JSON.stringify(recentReports)}`
  });
  return response.text || "Every report helps us protect our shared natural environment.";
};

