const ChatSentinel: React.FC<{ user: any }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<any[]>([
    { role: 'model', text: `Greetings ${user.name}. I am the Sentinel. Monitoring neural channels for environmental anomalies. How can I assist your mission today?` }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, loading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, userMsg].map(m => ({ 
          role: m.role, 
          parts: [{ text: m.text }] 
        })),
        config: { 
          systemInstruction: "You are the EcoGuard Sentinel. Provide concise, professional, and action-oriented environmental advice. You represent a global network for ecological protection." 
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "The grid is stable. No immediate concerns detected." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Sub-optimal signal detected. Please check your network bridge and retry." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-12 right-12 z-[200]">
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[400px] h-[600px] bg-white rounded-[3rem] shadow-[0_50px_100px_rgba(0,0,0,0.2)] border border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 duration-500">
