import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { User } from '../types.ts';

interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

const ChatSentinel: React.FC<{ user: User }> = ({ user }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: `Greetings, ${user.name}. I am the Sentinel AI. How can I assist with environmental monitoring today?`, timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage: Message = { role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, userMessage].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: "You are the EcoGuard Sentinel AI. Provide professional, concise, and action-oriented environmental advice." }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "I am processing the data stream...", timestamp: new Date() }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Signal interference detected. Please try again.", timestamp: new Date() }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-12 right-12 z-[100]">
      {isOpen && (
        <div className="absolute bottom-20 right-0 w-[380px] h-[550px] bg-slate-900 rounded-[3rem] border border-white/10 flex flex-col overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10 fade-in duration-500">
          <div className="p-8 bg-gradient-to-r from-slate-800 to-emerald-900 border-b border-white/5 flex items-center justify-between text-white">
            <h3 className="font-black">Sentinel AI</h3>
            <button onClick={() => setIsOpen(false)} className="opacity-60 hover:opacity-100">Close</button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-900/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-5 rounded-[2rem] text-sm ${m.role === 'user' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white/5 text-slate-300 border border-white/5'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && <div className="text-[10px] font-black text-emerald-500 uppercase tracking-widest animate-pulse">Sentinel Thinking...</div>}
          </div>
          <form onSubmit={handleSendMessage} className="p-6 border-t border-white/5 bg-slate-900">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              placeholder="Query the grid..." 
              className="w-full bg-slate-800 border border-white/10 rounded-2xl px-6 py-4 text-white outline-none focus:ring-2 focus:ring-emerald-500/20" 
            />
          </form>
        </div>
      )}
      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className="w-16 h-16 rounded-full bg-emerald-600 flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 border-4 border-white"
      >
        <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2.5"/></svg>
      </button>
    </div>
  );
};

export default ChatSentinel;

import React, { useState, useRef, useEffect } from 'react';
import { analyzeEnvironmentalImage } from '../services/geminiService.ts';
import { AIAnalysisResult, IncidentType, Severity, Report } from '../types.ts';

interface ReportWizardProps {
  onComplete: (report: Partial<Report>) => void;
}

const ReportWizard: React.FC<ReportWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [image, setImage] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [analysis, setAnalysis] = useState<AIAnalysisResult | null>(null);
  const [description, setDescription] = useState('');
  const [manualAddress, setManualAddress] = useState('');
  const [location, setLocation] = useState<{lat: number, lng: number, address: string} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const initialAddr = "Coordinates Locked.";
        setLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
          address: initialAddr
        });
        setManualAddress(initialAddr);
      }, () => {
        setManualAddress("Manual Input Required");
      });
    }
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setStep(2);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStartAnalysis = async () => {
    if (!image) return;
    setAnalyzing(true);
    try {
      const base64Data = image.split(',')[1];
      const result = await analyzeEnvironmentalImage(base64Data);
      setAnalysis(result);
      setStep(3);
    } catch (err) {
      alert("AI analysis failed. Please enter details manually.");
      setStep(3);
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSubmit = () => {
    onComplete({
      type: analysis?.detectedType || IncidentType.OTHER,
      severity: analysis?.severity || Severity.MEDIUM,
      description: description || analysis?.explanation || '',
      imageUrl: image || undefined,
      aiInsights: analysis?.explanation,
      location: { 
        lat: location?.lat || 0, 
        lng: location?.lng || 0, 
        address: manualAddress || location?.address || "Manual Input" 
      },
      timestamp: new Date(),
    });
  };

  return (
    <div className="bg-white rounded-[3rem] p-10 shadow-2xl max-w-xl mx-auto border border-emerald-100 animate-slide-up">
      <div className="flex items-center gap-4 mb-10">
        {[1, 2, 3].map((s) => (
          <div key={s} className="flex-1 h-2 rounded-full bg-slate-100 overflow-hidden">
            <div className={`h-full transition-all duration-700 ${step >= s ? 'bg-emerald-500' : 'bg-transparent'}`} />
          </div>
        ))}
      </div>

      {step === 1 && (
        <div className="text-center py-10">
          <div className="w-24 h-24 bg-emerald-50 rounded-[2rem] flex items-center justify-center mx-auto mb-8 text-emerald-600 shadow-inner">
            <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
          </div>
          <h2 className="text-3xl font-black mb-4 tracking-tight">Capture Evidence</h2>
          <p className="text-slate-500 mb-10 font-medium">Upload an image of the incident.</p>
          <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
          <button onClick={() => fileInputRef.current?.click()} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl shadow-xl hover:bg-black transition-all">Select Media</button>
        </div>
      )}

      {step === 2 && image && (
        <div className="text-center">
          <img src={image} className="w-full aspect-square object-cover rounded-[2.5rem] shadow-2xl mb-8" alt="Evidence" />
          <h2 className="text-2xl font-black mb-8">AI Vision Scan</h2>
          <div className="flex gap-4">
            <button disabled={analyzing} onClick={handleStartAnalysis} className="flex-1 bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg hover:bg-indigo-700 disabled:opacity-50 transition-all">
              {analyzing ? "Synthesizing..." : "Run AI Scan"}
            </button>
            <button disabled={analyzing} onClick={() => setStep(3)} className="px-8 border border-slate-200 font-black py-4 rounded-2xl text-slate-400">Skip</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Location Address</label>
              <input 
                type="text" 
                value={manualAddress} 
                onChange={(e) => setManualAddress(e.target.value)}
                placeholder="Site address..."
                className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-black text-slate-800 outline-none"
              />
          </div>
          <div className="grid grid-cols-2 gap-4">
             <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Type</p>
                <p className="text-xs font-black text-slate-900">{analysis?.detectedType || 'Other'}</p>
             </div>
             <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Severity</p>
                <p className="text-xs font-black text-red-600">{analysis?.severity || 'Medium'}</p>
             </div>
          </div>
          <textarea 
            value={description} 
            onChange={(e) => setDescription(e.target.value)} 
            placeholder="Field observations..." 
            className="w-full bg-slate-50 border border-slate-100 rounded-3xl p-6 font-bold text-slate-900 outline-none min-h-[120px]" 
          />
          <button onClick={handleSubmit} className="w-full bg-emerald-600 text-white font-black py-5 rounded-[2rem] shadow-2xl hover:bg-emerald-700 transition-all">Submit Report</button>
        </div>
      )}
