import React, { useState, useMemo } from 'react';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import ReportWizard from './components/ReportWizard.tsx';
import Login from './components/Login.tsx';
import SystemInsights from './components/SystemInsights.tsx';
import Resources from './components/Resources.tsx';
import ChatSentinel from './components/ChatSentinel.tsx';
import { User, Report, Severity, IncidentType, ReportStatus, TimelineEvent } from './types.ts';

const AUTHORITIES = ["Forestry Commission", "Wildlife Rescue Unit", "EPA Response Team", "Municipal Parks Dept"];

const INITIAL_REPORTS: Report[] = [
  {
    id: 'R-902',
    type: IncidentType.ILLEGAL_LOGGING,
    severity: Severity.HIGH,
    description: 'Fresh tree stumps and heavy tire marks detected in the protected buffer zone.',
    location: { lat: 45.523, lng: -122.676, address: "Northern Ridge Biosphere, Sector 7" },
    timestamp: new Date(Date.now() - 7200000),
    imageUrl: 'https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?auto=format&fit=crop&q=80&w=800',
    status: 'assigned',
    reporterId: 'user-001',
    assignedAuthorityId: 'Forestry Commission',
    aiInsights: 'Vision analysis confirms recent logging activity in a restricted zone.',
    timeline: [
      { status: 'pending', timestamp: new Date(Date.now() - 7200000), message: 'Incident reported by Sentinel.', actor: 'John Sentinel' },
      { status: 'assigned', timestamp: new Date(Date.now() - 3600000), message: 'Admin assigned case to Forestry Commission.', actor: 'Chief Warden' }
    ]
  }
];

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [reports, setReports] = useState<Report[]>(INITIAL_REPORTS);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    setIsAuthenticated(true);
  };

  const handleNewReport = (reportData: Partial<Report>) => {
    const newReport: Report = {
      ...reportData,
      id: `R-${Math.floor(Math.random() * 900) + 100}`,
      status: 'pending',
      reporterId: user?.id || 'anonymous',
      timestamp: reportData.timestamp || new Date(),
      timeline: [{
        status: 'pending',
        timestamp: new Date(),
        message: 'Incident reported. Dispatched to Global Command for triage.',
        actor: user?.name || 'Anonymous'
      }]
    } as Report;
    setReports([newReport, ...reports]);
    setActiveTab('reports');
  };

  const handleUpdateStatus = (id: string, newStatus: ReportStatus, message: string, actor: string, extraData?: any) => {
    setReports(prev => prev.map(r => {
      if (r.id === id) {
        const newEvent: TimelineEvent = {
          status: newStatus,
          timestamp: new Date(),
          message,
          actor
        };
        return {
          ...r,
          status: newStatus,
          timeline: [...r.timeline, newEvent],
          ...extraData
        };
      }
      return r;
    }));
  };

  const visibleReports = useMemo(() => {
    if (!user) return [];
    if (user.role === 'admin') return reports;
    if (user.role === 'authority') return reports.filter(r => r.assignedAuthorityId === user.organization);
    return reports.filter(r => r.reporterId === user.id);
  }, [reports, user]);

  if (!isAuthenticated || !user) return <Login onLoginSuccess={handleAuthSuccess} />;

  return (
    <Layout user={user} onLogout={() => setIsAuthenticated(false)} activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && (
        <Dashboard 
          reports={reports} 
          user={user} 
          onNewReport={() => setActiveTab('report')} 
          onNavigate={(t) => setActiveTab(t)} 
        />
      )}

      {activeTab === 'report' && <ReportWizard onComplete={handleNewReport} />}

      {activeTab === 'reports' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-slate-900 p-10 rounded-[3rem] text-white flex justify-between items-center shadow-2xl">
            <div>
              <h2 className="text-3xl font-black tracking-tight">Operational Feed</h2>
              <p className="text-slate-400 font-medium">Monitoring {visibleReports.length} active anomalies in your sector.</p>
            </div>
            <div className="px-6 py-2 bg-white/10 rounded-xl text-[10px] font-black uppercase tracking-widest border border-white/10">
              Grid Secure
            </div>
          </div>

          <div className="grid gap-8">
            {visibleReports.length === 0 && (
              <div className="text-center py-20 bg-slate-100 rounded-[3rem] border border-dashed border-slate-300">
                <p className="font-black text-slate-400 uppercase tracking-widest">No reports found.</p>
              </div>
            )}
            {visibleReports.map(r => (
              <div key={r.id} className="bg-white rounded-[3rem] border border-slate-200 shadow-xl overflow-hidden flex flex-col md:flex-row group transition-all hover:shadow-2xl">
                <div className="md:w-1/3 h-64 md:h-auto relative">
                  <img src={r.imageUrl} className="w-full h-full object-cover" alt="Incident" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                  <div className="absolute bottom-6 left-6">
                    <span className="px-3 py-1 bg-emerald-500 rounded-lg text-[10px] font-black text-white uppercase tracking-widest">
                      {r.type}
                    </span>
                  </div>
                </div>
                <div className="flex-1 p-10 flex flex-col justify-between">
                  <div>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center gap-3">
                        <div className={`w-3 h-3 rounded-full animate-pulse ${r.status === 'resolved' ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Status: {r.status}</span>
                      </div>
                      <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">#{r.id}</span>
                    </div>
                    <h3 className="text-2xl font-black text-slate-900 mb-4">{r.location.address}</h3>
                    <p className="text-slate-500 font-medium italic mb-6 leading-relaxed">"{r.description}"</p>
                    {r.aiInsights && (
                      <div className="p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                         <p className="text-[9px] font-black text-indigo-600 uppercase tracking-widest mb-1">AI Sentinel Insight</p>
                         <p className="text-xs font-bold text-indigo-900">{r.aiInsights}</p>
                      </div>
                    )}
                  </div>

                  <div className="mt-8 pt-6 border-t border-slate-50">
                    {user.role === 'admin' && r.status === 'pending' && (
                      <div className="flex flex-wrap gap-2">
                        {AUTHORITIES.map(auth => (
                          <button key={auth} 
                            onClick={() => handleUpdateStatus(r.id, 'assigned', `Admin assigned report to ${auth}.`, 'Admin', { assignedAuthorityId: auth })}
                            className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700">
                            Assign {auth}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'notes' && <Resources />}
      {activeTab === 'leaderboard' && <SystemInsights />}
      <ChatSentinel user={user} />
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysisResult, IncidentType, Severity } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeEnvironmentalImage = async (base64Image: string): Promise<AIAnalysisResult> => {
  const model = 'gemini-3-flash-preview';

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Analyze this image for environmental or wildlife concerns. 
          Identify if it shows land damage, illegal tree cutting, injured animals, or road accidents. 
          Assess the severity and provide a short explanation and recommended immediate action.`,
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          detectedType: {
            type: Type.STRING,
            description: "Category of the incident",
          },
          severity: {
            type: Type.STRING,
            description: "Severity level",
          },
          explanation: {
            type: Type.STRING,
            description: "Concise description",
          },
          recommendedAction: {
            type: Type.STRING,
            description: "Recommendation",
          },
        },
        required: ["detectedType", "severity", "explanation", "recommendedAction"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Could not interpret AI analysis.");
  try {
    return JSON.parse(text) as AIAnalysisResult;
  } catch (e) {
    console.error("Failed to parse JSON from AI response:", text);
    throw new Error("Invalid AI response format.");
  }
};

export const generateCommunityUpdate = async (recentReports: any[]) => {
  const model = 'gemini-3-flash-preview';
  const response = await ai.models.generateContent({
    model,
    contents: `Write a short, inspiring 2-sentence summary for a community dashboard based on these environmental incidents: ${JSON.stringify(recentReports)}`
  });
  return response.text || "The grid is stable. Vigilance continues.";
};
